package main

import (
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ViewType represents the different tool views available in the multitool
type ViewType int

const (
	ViewOverview ViewType = iota
	ViewSystemMonitor
	ViewPortScanner
	ViewPackageManager
	ViewContainerMgmt
	ViewAIAssistant
	ViewBashTerminal
	ViewSettings
)

// String returns the string representation of ViewType
func (v ViewType) String() string {
	switch v {
	case ViewOverview:
		return "overview"
	case ViewSystemMonitor:
		return "system"
	case ViewPortScanner:
		return "scanner"
	case ViewPackageManager:
		return "packages"
	case ViewContainerMgmt:
		return "containers"
	case ViewAIAssistant:
		return "ai"
	case ViewBashTerminal:
		return "bash"
	case ViewSettings:
		return "settings"
	default:
		return "unknown"
	}
}

// ToolComponent defines the interface that all tool components must implement
type ToolComponent interface {
	// Init initializes the component and returns initial commands
	Init() tea.Cmd

	// Update handles messages and returns updated model and commands
	Update(msg tea.Msg) (ToolComponent, tea.Cmd)

	// View renders the component's interface
	View() string

	// SetSize updates the component's dimensions
	SetSize(width, height int)

	// GetViewType returns the component's view type
	GetViewType() ViewType

	// IsActive returns whether the component is currently active
	IsActive() bool

	// SetActive sets the component's active state
	SetActive(active bool)
}

// Global message types for inter-component communication
type (
	// tickMsg represents a tick message for animations and updates
	tickMsg time.Time
	// ViewSwitchMsg is sent when switching between different tool views
	ViewSwitchMsg struct {
		View     ViewType
		Previous ViewType
	}

	// ConfigUpdateMsg is sent when configuration changes
	ConfigUpdateMsg struct {
		Config *Config
	}

	// NotificationMsg is sent to display notifications to the user
	NotificationMsg struct {
		Message string
		Level   NotificationLevel
		Source  string
		Time    time.Time
	}

	// StatusUpdateMsg is sent to update the status bar
	StatusUpdateMsg struct {
		Status string
		Color  lipgloss.Color
	}

	// ErrorMsg wraps errors for consistent error handling
	ErrorMsg struct {
		Err    error
		Source string
		Level  ErrorLevel
	}

	// DataUpdateMsg is sent when shared data is updated
	DataUpdateMsg struct {
		Type string
		Data interface{}
	}
)

// NotificationLevel represents the severity of notifications
type NotificationLevel int

const (
	NotificationInfo NotificationLevel = iota
	NotificationWarning
	NotificationError
	NotificationSuccess
)

// String returns the string representation of NotificationLevel
func (n NotificationLevel) String() string {
	switch n {
	case NotificationInfo:
		return "info"
	case NotificationWarning:
		return "warning"
	case NotificationError:
		return "error"
	case NotificationSuccess:
		return "success"
	default:
		return "unknown"
	}
}

// ErrorLevel represents the severity of errors
type ErrorLevel int

const (
	ErrorLevelInfo ErrorLevel = iota
	ErrorLevelWarning
	ErrorLevelError
	ErrorLevelCritical
)

// String returns the string representation of ErrorLevel
func (e ErrorLevel) String() string {
	switch e {
	case ErrorLevelInfo:
		return "info"
	case ErrorLevelWarning:
		return "warning"
	case ErrorLevelError:
		return "error"
	case ErrorLevelCritical:
		return "critical"
	default:
		return "unknown"
	}
}

// KeyBindings holds all key binding configurations
type KeyBindings struct {
	Quit       []string
	Help       []string
	Search     []string
	Kill       []string
	SwitchView []string
	Navigate   []string
	Select     []string
	Back       []string
}

// DefaultKeyBindings returns the default key binding configuration
func DefaultKeyBindings() KeyBindings {
	return KeyBindings{
		Quit:       []string{"q", "ctrl+c"},
		Help:       []string{"?", "h"},
		Search:     []string{"/"},
		Kill:       []string{"k"},
		SwitchView: []string{"tab"},
		Navigate:   []string{"up", "down", "j", "k"},
		Select:     []string{"enter", " "},
		Back:       []string{"esc"},
	}
}

// Config holds the application configuration
type Config struct {
	// UI preferences
	Theme        ThemeConfig       `yaml:"theme"`
	KeyBindings  KeyBindings       `yaml:"keybindings"`
	RefreshRates RefreshRateConfig `yaml:"refresh_rates"`

	// Tool-specific settings
	SystemMonitor  SystemMonitorConfig  `yaml:"system_monitor"`
	PortScanner    PortScannerConfig    `yaml:"port_scanner"`
	PackageManager PackageManagerConfig `yaml:"package_manager"`
	ContainerMgmt  ContainerMgmtConfig  `yaml:"container_mgmt"`
	AIAssistant    AIAssistantConfig    `yaml:"ai_assistant"`

	// Global settings
	LogLevel        string `yaml:"log_level"`
	DataDirectory   string `yaml:"data_directory"`
	PluginDirectory string `yaml:"plugin_directory"`
}

// ThemeConfig holds theme-related configuration
type ThemeConfig struct {
	Primary    string `yaml:"primary"`
	Secondary  string `yaml:"secondary"`
	Accent     string `yaml:"accent"`
	Success    string `yaml:"success"`
	Warning    string `yaml:"warning"`
	Danger     string `yaml:"danger"`
	Background string `yaml:"background"`
	Text       string `yaml:"text"`
}

// RefreshRateConfig holds refresh rate settings for different components
type RefreshRateConfig struct {
	SystemStats time.Duration `yaml:"system_stats"`
	Processes   time.Duration `yaml:"processes"`
	Network     time.Duration `yaml:"network"`
	Alerts      time.Duration `yaml:"alerts"`
}

// Tool-specific configuration types
type SystemMonitorConfig struct {
	ShowProcesses   bool          `yaml:"show_processes"`
	ProcessLimit    int           `yaml:"process_limit"`
	RefreshInterval time.Duration `yaml:"refresh_interval"`
}

type PortScannerConfig struct {
	DefaultTimeout    time.Duration `yaml:"default_timeout"`
	MaxConcurrency    int           `yaml:"max_concurrency"`
	DefaultPortRanges []string      `yaml:"default_port_ranges"`
}

type PackageManagerConfig struct {
	EnabledManagers []string `yaml:"enabled_managers"`
	AutoUpdate      bool     `yaml:"auto_update"`
	CheckSecurity   bool     `yaml:"check_security"`
}

type ContainerMgmtConfig struct {
	DockerSocket         string `yaml:"docker_socket"`
	ShowSystemContainers bool   `yaml:"show_system_containers"`
}

type AIAssistantConfig struct {
	Provider    string  `yaml:"provider"`
	APIKey      string  `yaml:"api_key"`
	Model       string  `yaml:"model"`
	MaxTokens   int     `yaml:"max_tokens"`
	Temperature float64 `yaml:"temperature"`
}

// DefaultConfig returns a default configuration
func DefaultConfig() *Config {
	return &Config{
		Theme: ThemeConfig{
			Primary:    "#6366f1",
			Secondary:  "#8b5cf6",
			Accent:     "#06b6d4",
			Success:    "#10b981",
			Warning:    "#f59e0b",
			Danger:     "#ef4444",
			Background: "#0f0f23",
			Text:       "#e2e8f0",
		},
		KeyBindings: DefaultKeyBindings(),
		RefreshRates: RefreshRateConfig{
			SystemStats: 2 * time.Second,
			Processes:   2 * time.Second,
			Network:     3 * time.Second,
			Alerts:      5 * time.Second,
		},
		SystemMonitor: SystemMonitorConfig{
			ShowProcesses:   true,
			ProcessLimit:    100,
			RefreshInterval: 2 * time.Second,
		},
		PortScanner: PortScannerConfig{
			DefaultTimeout:    5 * time.Second,
			MaxConcurrency:    100,
			DefaultPortRanges: []string{"1-1000", "3000-3100", "8000-8100"},
		},
		PackageManager: PackageManagerConfig{
			EnabledManagers: []string{"npm", "go", "pip"},
			AutoUpdate:      false,
			CheckSecurity:   true,
		},
		ContainerMgmt: ContainerMgmtConfig{
			DockerSocket:         "/var/run/docker.sock",
			ShowSystemContainers: false,
		},
		AIAssistant: AIAssistantConfig{
			Provider:    "openai",
			Model:       "gpt-3.5-turbo",
			MaxTokens:   2000,
			Temperature: 0.7,
		},
		LogLevel:        "info",
		DataDirectory:   "~/.terminal-multitool",
		PluginDirectory: "~/.terminal-multitool/plugins",
	}
}

package main

import (
	"fmt"
	"strings"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// StatusBarModel implementation

// Init initializes the status bar
func (s *StatusBarModel) Init() tea.Cmd {
	return nil
}

// Update handles status bar messages
func (s *StatusBarModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case StatusUpdateMsg:
		s.UpdateStatus(msg.Status, msg.Color)
	}
	return s, nil
}

// View renders the status bar
func (s *StatusBarModel) View() string {
	if s.width == 0 {
		return ""
	}

	// Create status bar with current status and timestamp
	statusText := fmt.Sprintf("Status: %s", s.status)
	timeText := s.timestamp.Format("15:04:05")

	// Calculate spacing
	totalUsed := len(statusText) + len(timeText)
	spacing := s.width - totalUsed - 2
	if spacing < 0 {
		spacing = 0
	}

	statusStyle := lipgloss.NewStyle().
		Foreground(s.color).
		Bold(true)

	timeStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8"))

	content := statusStyle.Render(statusText) +
		strings.Repeat(" ", spacing) +
		timeStyle.Render(timeText)

	return lipgloss.NewStyle().
		Background(lipgloss.Color("#1e1e3f")).
		Foreground(lipgloss.Color("#e2e8f0")).
		Width(s.width).
		Padding(0, 1).
		Render(content)
}

// SetSize sets the status bar width
func (s *StatusBarModel) SetSize(width, height int) {
	s.width = width
}

// UpdateStatus updates the status bar content
func (s *StatusBarModel) UpdateStatus(status string, color lipgloss.Color) {
	s.status = status
	s.color = color
	s.timestamp = time.Now()
}

// NavigationModel implementation

// Init initializes the navigation component
func (n *NavigationModel) Init() tea.Cmd {
	return nil
}

// Update handles navigation messages
func (n *NavigationModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case ViewSwitchMsg:
		// Update current index based on the new view
		for i, view := range n.views {
			if view.Type == msg.View {
				n.currentIndex = i
				break
			}
		}
	}
	return n, nil
}

// View renders the navigation tabs
func (n *NavigationModel) View() string {
	if n.width == 0 {
		return ""
	}

	var tabStrs []string

	for i, view := range n.views {
		content := view.KeyBinding + " " + view.Name
		if n.showIcons {
			content = view.Icon + " " + content
		}

		if i == n.currentIndex {
			// Active tab with elegant styling
			tabStrs = append(tabStrs, lipgloss.NewStyle().
				Foreground(lipgloss.Color("#0f0f23")).
				Background(view.Color).
				Bold(true).
				Padding(0, 2).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(view.Color).
				Render(content))
		} else {
			// Inactive tab with subtle styling
			tabStrs = append(tabStrs, lipgloss.NewStyle().
				Foreground(view.Color).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#64748b")).
				Padding(0, 2).
				Render(content))
		}
	}

	// Join tabs horizontally with spacing
	tabsLine := lipgloss.JoinHorizontal(lipgloss.Center, tabStrs...)

	// Center the tabs
	return lipgloss.NewStyle().
		Width(n.width).
		Align(lipgloss.Center).
		Render(tabsLine) + "\n"
}

// SetSize sets the navigation component size
func (n *NavigationModel) SetSize(width, height int) {
	n.width = width
}

// GetCurrentView returns the currently selected view
func (n *NavigationModel) GetCurrentView() ViewType {
	if n.currentIndex >= 0 && n.currentIndex < len(n.views) {
		return n.views[n.currentIndex].Type
	}
	return ViewOverview
}

// NotificationModel implementation

// Init initializes the notification component
func (n *NotificationModel) Init() tea.Cmd {
	return nil
}

// Update handles notification messages
func (n *NotificationModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case NotificationMsg:
		n.AddNotification(msg)
	case tickMsg:
		// Remove expired notifications
		n.cleanupExpiredNotifications()
	}
	return n, nil
}

// View renders the notifications
func (n *NotificationModel) View() string {
	if len(n.notifications) == 0 || n.width == 0 {
		return ""
	}

	var notificationStrs []string
	visibleCount := 0

	// Show most recent notifications first
	for i := len(n.notifications) - 1; i >= 0 && visibleCount < n.maxVisible; i-- {
		notification := n.notifications[i]
		if !notification.Visible {
			continue
		}

		// Determine notification style based on level
		var style lipgloss.Style
		var icon string

		switch notification.Level {
		case NotificationError:
			style = lipgloss.NewStyle().
				Foreground(lipgloss.Color("#ef4444")).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#ef4444"))
			icon = "❌"
		case NotificationWarning:
			style = lipgloss.NewStyle().
				Foreground(lipgloss.Color("#f59e0b")).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#f59e0b"))
			icon = "⚠️"
		case NotificationSuccess:
			style = lipgloss.NewStyle().
				Foreground(lipgloss.Color("#10b981")).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#10b981"))
			icon = "✅"
		default: // NotificationInfo
			style = lipgloss.NewStyle().
				Foreground(lipgloss.Color("#06b6d4")).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#06b6d4"))
			icon = "ℹ️"
		}

		// Format notification content
		timestamp := notification.Timestamp.Format("15:04")
		content := fmt.Sprintf("%s [%s] %s: %s",
			icon, timestamp, notification.Source, notification.Message)

		// Truncate if too long
		maxWidth := n.width - 4
		if len(content) > maxWidth {
			content = content[:maxWidth-3] + "..."
		}

		notificationStrs = append(notificationStrs,
			style.Padding(0, 1).Width(n.width-2).Render(content))

		visibleCount++
	}

	if len(notificationStrs) == 0 {
		return ""
	}

	// Join notifications vertically
	return lipgloss.JoinVertical(lipgloss.Left, notificationStrs...)
}

// SetSize sets the notification component size
func (n *NotificationModel) SetSize(width, height int) {
	n.width = width
	n.height = height
	// Adjust max visible based on height
	n.maxVisible = min(height/3, 10)
}

// AddNotification adds a new notification
func (n *NotificationModel) AddNotification(msg NotificationMsg) {
	// Generate unique ID
	id := fmt.Sprintf("%d-%s", time.Now().UnixNano(), msg.Source)

	// Default duration based on level
	duration := 5 * time.Second
	switch msg.Level {
	case NotificationError:
		duration = 10 * time.Second
	case NotificationWarning:
		duration = 7 * time.Second
	case NotificationSuccess:
		duration = 3 * time.Second
	}

	notification := Notification{
		ID:        id,
		Message:   msg.Message,
		Level:     msg.Level,
		Source:    msg.Source,
		Timestamp: msg.Time,
		Duration:  duration,
		Visible:   true,
	}

	n.notifications = append(n.notifications, notification)

	// Limit total notifications to prevent memory issues
	if len(n.notifications) > 50 {
		n.notifications = n.notifications[len(n.notifications)-50:]
	}
}

// cleanupExpiredNotifications removes expired notifications
func (n *NotificationModel) cleanupExpiredNotifications() {
	now := time.Now()
	var activeNotifications []Notification

	for _, notification := range n.notifications {
		if now.Sub(notification.Timestamp) < notification.Duration {
			activeNotifications = append(activeNotifications, notification)
		}
	}

	n.notifications = activeNotifications
}

// ClearNotifications clears all notifications
func (n *NotificationModel) ClearNotifications() {
	n.notifications = make([]Notification, 0)
}

// GetNotificationCount returns the number of visible notifications
func (n *NotificationModel) GetNotificationCount() int {
	count := 0
	for _, notification := range n.notifications {
		if notification.Visible {
			count++
		}
	}
	return count
}

