	// Global settings
	LogLevel        string `yaml:"log_level"`
	DataDirectory   string `yaml:"data_directory"`
	PluginDirectory string `yaml:"plugin_directory"`
}

// ThemeConfig holds theme-related configuration
type ThemeConfig struct {
