    81→
    82→	// Restore new component state
    83→	vm.restoreComponentState(newView)
    84→
    85→	// Activate new component
    86→	if newComponent := vm.GetCurrentComponent(); newComponent != nil {
    87→		newComponent.SetActive(true)
