   133→// RouteMessage routes a message to the appropriate component
   134→func (vm *ViewManager) RouteMessage(msg tea.Msg) ([]ToolComponent, []tea.Cmd) {
   135→	var updatedComponents []ToolComponent
   136→	var cmds []tea.Cmd
   137→
   138→	switch msg := msg.(type) {
