   144→
   145→	case tea.WindowSizeMsg:
   146→		// Update size for all components
   147→		vm.SetSize(msg.Width, msg.Height)
   148→
   149→	default:
   150→		// Route to current component
   151→		if currentComponent := vm.GetCurrentComponent(); currentComponent != nil {
   152→			updatedComponent, cmd := currentComponent.Update(msg)
   153→			if updatedComponent != nil {
   154→				vm.components[vm.currentView] = updatedComponent
   155→				updatedComponents = append(updatedComponents, updatedComponent)
   156→			}
   157→			if cmd != nil {
   158→				cmds = append(cmds, cmd)
   159→			}
   160→		}
   161→
   162→		// Also route global messages to all components that need them
   163→		vm.routeGlobalMessage(msg, &updatedComponents, &cmds)
   164→	}
   165→
   166→	return updatedComponents, cmds
   167→}
