package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"gopkg.in/yaml.v3"
)

// ConfigManager handles configuration loading, validation, and saving
type ConfigManager struct {
	configPath      string
	defaultConfig   *Config
	migrationRules  []MigrationRule
	validators      map[string]ConfigValidator
	schemaVersion   int
}

// ConfigValidator defines a function to validate a configuration field
type ConfigValidator func(value interface{}) error

// MigrationRule defines how to migrate configuration between versions
type MigrationRule struct {
	FromVersion int
	ToVersion   int
	Migrate     func(*Config) error
}

// ConfigurationError represents configuration-related errors
type ConfigurationError struct {
	Field   string
	Message string
	Value   interface{}
}

func (e *ConfigurationError) Error() string {
	return fmt.Sprintf("configuration error in field '%s': %s (value: %v)", e.Field, e.Message, e.Value)
}

// NewConfigManager creates a new configuration manager
func NewConfigManager(configPath string) *ConfigManager {
	cm := &ConfigManager{
		configPath:      configPath,
		defaultConfig:   DefaultConfig(),
		migrationRules:  make([]MigrationRule, 0),
		validators:      make(map[string]ConfigValidator),
		schemaVersion:   1, // Current schema version
	}

	// Register default validators
	cm.registerDefaultValidators()

	// Register migration rules
	cm.registerMigrationRules()

	return cm
}

// registerDefaultValidators sets up validation rules for configuration fields
func (cm *ConfigManager) registerDefaultValidators() {
	// Theme validation
	cm.validators["theme.primary"] = cm.validateColor
	cm.validators["theme.secondary"] = cm.validateColor
	cm.validators["theme.accent"] = cm.validateColor
	cm.validators["theme.success"] = cm.validateColor
	cm.validators["theme.warning"] = cm.validateColor
	cm.validators["theme.danger"] = cm.validateColor
	cm.validators["theme.background"] = cm.validateColor
	cm.validators["theme.text"] = cm.validateColor

	// Refresh rate validation
	cm.validators["refresh_rates.system_stats"] = cm.validateDuration
	cm.validators["refresh_rates.processes"] = cm.validateDuration
	cm.validators["refresh_rates.network"] = cm.validateDuration
	cm.validators["refresh_rates.alerts"] = cm.validateDuration

	// Port scanner validation
	cm.validators["port_scanner.default_timeout"] = cm.validateDuration
	cm.validators["port_scanner.max_concurrency"] = cm.validatePositiveInt
	cm.validators["port_scanner.default_port_ranges"] = cm.validatePortRanges

	// System monitor validation
	cm.validators["system_monitor.process_limit"] = cm.validatePositiveInt
	cm.validators["system_monitor.refresh_interval"] = cm.validateDuration

	// AI assistant validation
	cm.validators["ai_assistant.provider"] = cm.validateAIProvider
	cm.validators["ai_assistant.max_tokens"] = cm.validatePositiveInt
	cm.validators["ai_assistant.temperature"] = cm.validateTemperature

	// Log level validation
	cm.validators["log_level"] = cm.validateLogLevel

	// Directory validation
	cm.validators["data_directory"] = cm.validateDirectory
	cm.validators["plugin_directory"] = cm.validateDirectory
}

// registerMigrationRules sets up configuration migration rules
func (cm *ConfigManager) registerMigrationRules() {
	// Example migration from version 1 to 2
	cm.migrationRules = append(cm.migrationRules, MigrationRule{
		FromVersion: 1,
		ToVersion:   2,
		Migrate: func(config *Config) error {
			// Example: If we add a new field in version 2
			// config.NewField = "default_value"
			return nil
		},
	})
}

// LoadConfig loads configuration from file with validation and migration
func (cm *ConfigManager) LoadConfig() (*Config, error) {
	// Check if config file exists
	if _, err := os.Stat(cm.configPath); os.IsNotExist(err) {
		// Create default configuration
		config := cm.defaultConfig
		if err := cm.SaveConfig(config); err != nil {
			return nil, fmt.Errorf("failed to create default config: %w", err)
		}
		return config, nil
	}

	// Read config file
	data, err := os.ReadFile(cm.configPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file: %w", err)
	}

	// Parse YAML
	var config Config
	if err := yaml.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("failed to parse config file: %w", err)
	}

	// Validate configuration
	if err := cm.ValidateConfig(&config); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	// Apply migrations if needed
	if err := cm.applyMigrations(&config); err != nil {
		return nil, fmt.Errorf("configuration migration failed: %w", err)
	}

	return &config, nil
}

// SaveConfig saves configuration to file
func (cm *ConfigManager) SaveConfig(config *Config) error {
	// Ensure directory exists
	if err := os.MkdirAll(filepath.Dir(cm.configPath), 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	// Validate before saving
	if err := cm.ValidateConfig(config); err != nil {
		return fmt.Errorf("configuration validation failed: %w", err)
	}

	// Marshal to YAML
	data, err := yaml.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal config: %w", err)
	}

	// Write to file atomically
	tempFile := cm.configPath + ".tmp"
	if err := os.WriteFile(tempFile, data, 0644); err != nil {
		return fmt.Errorf("failed to write config file: %w", err)
	}

	// Atomic move
	if err := os.Rename(tempFile, cm.configPath); err != nil {
		os.Remove(tempFile) // Cleanup temp file
		return fmt.Errorf("failed to save config file: %w", err)
	}

	return nil
}

// ValidateConfig validates the entire configuration
func (cm *ConfigManager) ValidateConfig(config *Config) error {
	// Validate theme
	if err := cm.validateField("theme.primary", config.Theme.Primary); err != nil {
		return err
	}
	if err := cm.validateField("theme.secondary", config.Theme.Secondary); err != nil {
		return err
	}
	if err := cm.validateField("theme.accent", config.Theme.Accent); err != nil {
		return err
	}
	if err := cm.validateField("theme.success", config.Theme.Success); err != nil {
		return err
	}
	if err := cm.validateField("theme.warning", config.Theme.Warning); err != nil {
		return err
	}
	if err := cm.validateField("theme.danger", config.Theme.Danger); err != nil {
		return err
	}
	if err := cm.validateField("theme.background", config.Theme.Background); err != nil {
		return err
	}
	if err := cm.validateField("theme.text", config.Theme.Text); err != nil {
		return err
	}

	// Validate refresh rates
	if err := cm.validateField("refresh_rates.system_stats", config.RefreshRates.SystemStats); err != nil {
		return err
	}
	if err := cm.validateField("refresh_rates.processes", config.RefreshRates.Processes); err != nil {
		return err
	}
	if err := cm.validateField("refresh_rates.network", config.RefreshRates.Network); err != nil {
		return err
	}
	if err := cm.validateField("refresh_rates.alerts", config.RefreshRates.Alerts); err != nil {
		return err
	}

	// Validate system monitor
	if err := cm.validateField("system_monitor.process_limit", config.SystemMonitor.ProcessLimit); err != nil {
		return err
	}
	if err := cm.validateField("system_monitor.refresh_interval", config.SystemMonitor.RefreshInterval); err != nil {
		return err
	}

	// Validate port scanner
	if err := cm.validateField("port_scanner.default_timeout", config.PortScanner.DefaultTimeout); err != nil {
		return err
	}
	if err := cm.validateField("port_scanner.max_concurrency", config.PortScanner.MaxConcurrency); err != nil {
		return err
	}
	if err := cm.validateField("port_scanner.default_port_ranges", config.PortScanner.DefaultPortRanges); err != nil {
		return err
	}

	// Validate AI assistant
	if err := cm.validateField("ai_assistant.provider", config.AIAssistant.Provider); err != nil {
		return err
	}
	if err := cm.validateField("ai_assistant.max_tokens", config.AIAssistant.MaxTokens); err != nil {
		return err
	}
	if err := cm.validateField("ai_assistant.temperature", config.AIAssistant.Temperature); err != nil {
		return err
	}

	// Validate global settings
	if err := cm.validateField("log_level", config.LogLevel); err != nil {
		return err
	}
	if err := cm.validateField("data_directory", config.DataDirectory); err != nil {
		return err
	}
	if err := cm.validateField("plugin_directory", config.PluginDirectory); err != nil {
		return err
	}

	return nil
}

// validateField validates a single configuration field
func (cm *ConfigManager) validateField(field string, value interface{}) error {
	validator, exists := cm.validators[field]
	if !exists {
		return nil // No validator for this field
	}

	if err := validator(value); err != nil {
		return &ConfigurationError{
			Field:   field,
			Message: err.Error(),
			Value:   value,
		}
	}

	return nil
}

// applyMigrations applies any necessary configuration migrations
func (cm *ConfigManager) applyMigrations(config *Config) error {
	// Get current schema version (assume 1 if not present)
	currentVersion := 1 // This would be read from the config in a real implementation

	// Apply migrations in sequence
	for currentVersion < cm.schemaVersion {
		migrated := false
		for _, rule := range cm.migrationRules {
			if rule.FromVersion == currentVersion {
				if err := rule.Migrate(config); err != nil {
					return fmt.Errorf("migration from version %d to %d failed: %w", 
						rule.FromVersion, rule.ToVersion, err)
				}
				currentVersion = rule.ToVersion
				migrated = true
				break
			}
		}

		if !migrated {
			return fmt.Errorf("no migration path found from version %d to %d", 
				currentVersion, cm.schemaVersion)
		}
	}

	return nil
}

// Configuration field validators

func (cm *ConfigManager) validateColor(value interface{}) error {
	colorStr, ok := value.(string)
	if !ok {
		return fmt.Errorf("color must be a string")
	}

	// Validate hex color format
	if !strings.HasPrefix(colorStr, "#") {
		return fmt.Errorf("color must start with #")
	}

	if len(colorStr) != 7 && len(colorStr) != 4 {
		return fmt.Errorf("color must be in format #RGB or #RRGGBB")
	}

	// Validate hex characters
	for _, r := range colorStr[1:] {
		if !((r >= '0' && r <= '9') || (r >= 'a' && r <= 'f') || (r >= 'A' && r <= 'F')) {
			return fmt.Errorf("invalid hex color format")
		}
	}

	return nil
}

func (cm *ConfigManager) validateDuration(value interface{}) error {
	switch v := value.(type) {
	case time.Duration:
		if v <= 0 {
			return fmt.Errorf("duration must be positive")
		}
	case string:
		if _, err := time.ParseDuration(v); err != nil {
			return fmt.Errorf("invalid duration format: %w", err)
		}
	default:
		return fmt.Errorf("duration must be a time.Duration or string")
	}
	return nil
}

func (cm *ConfigManager) validatePositiveInt(value interface{}) error {
	intVal, ok := value.(int)
	if !ok {
		return fmt.Errorf("value must be an integer")
	}

	if intVal <= 0 {
		return fmt.Errorf("value must be positive")
	}

	return nil
}

func (cm *ConfigManager) validatePortRanges(value interface{}) error {
	ranges, ok := value.([]string)
	if !ok {
		return fmt.Errorf("port ranges must be a string slice")
	}

	for _, rangeStr := range ranges {
		if err := cm.validatePortRange(rangeStr); err != nil {
			return fmt.Errorf("invalid port range '%s': %w", rangeStr, err)
		}
	}

	return nil
}

func (cm *ConfigManager) validatePortRange(rangeStr string) error {
	parts := strings.Split(rangeStr, "-")
	if len(parts) != 2 {
		return fmt.Errorf("port range must be in format 'start-end'")
	}

	start, err := parsePort(parts[0])
	if err != nil {
		return fmt.Errorf("invalid start port: %w", err)
	}

	end, err := parsePort(parts[1])
	if err != nil {
		return fmt.Errorf("invalid end port: %w", err)
	}

	if start > end {
		return fmt.Errorf("start port must be less than or equal to end port")
	}

	return nil
}

func parsePort(portStr string) (int, error) {
	port := 0
	for _, r := range portStr {
		if r < '0' || r > '9' {
			return 0, fmt.Errorf("port must be numeric")
		}
		port = port*10 + int(r-'0')
	}

	if port < 1 || port > 65535 {
		return 0, fmt.Errorf("port must be between 1 and 65535")
	}

	return port, nil
}

func (cm *ConfigManager) validateAIProvider(value interface{}) error {
	provider, ok := value.(string)
	if !ok {
		return fmt.Errorf("AI provider must be a string")
	}

	validProviders := []string{"openai", "anthropic", "local", "none"}
	for _, valid := range validProviders {
		if provider == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid AI provider, must be one of: %s", strings.Join(validProviders, ", "))
}

func (cm *ConfigManager) validateTemperature(value interface{}) error {
	temp, ok := value.(float64)
	if !ok {
		return fmt.Errorf("temperature must be a number")
	}

	if temp < 0.0 || temp > 2.0 {
		return fmt.Errorf("temperature must be between 0.0 and 2.0")
	}

	return nil
}

func (cm *ConfigManager) validateLogLevel(value interface{}) error {
	level, ok := value.(string)
	if !ok {
		return fmt.Errorf("log level must be a string")
	}

	validLevels := []string{"debug", "info", "warn", "error"}
	for _, valid := range validLevels {
		if level == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid log level, must be one of: %s", strings.Join(validLevels, ", "))
}

func (cm *ConfigManager) validateDirectory(value interface{}) error {
	dir, ok := value.(string)
	if !ok {
		return fmt.Errorf("directory must be a string")
	}

	if dir == "" {
		return fmt.Errorf("directory cannot be empty")
	}

	// Expand tilde
	if strings.HasPrefix(dir, "~/") {
		homeDir, err := os.UserHomeDir()
		if err != nil {
			return fmt.Errorf("cannot resolve home directory: %w", err)
		}
		dir = filepath.Join(homeDir, dir[2:])
	}

	// Check if directory exists or can be created
	info, err := os.Stat(dir)
	if err != nil {
		// Try to create the directory
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("cannot create directory: %w", err)
		}
		return nil
	}

	if !info.IsDir() {
		return fmt.Errorf("path exists but is not a directory")
	}

	// Check if directory is writable
	testFile := filepath.Join(dir, ".write_test")
	if err := os.WriteFile(testFile, []byte("test"), 0644); err != nil {
		return fmt.Errorf("directory is not writable: %w", err)
	}
	os.Remove(testFile) // Cleanup

	return nil
}

// Hot reload functionality

// WatchConfig watches for configuration file changes and reloads automatically
func (cm *ConfigManager) WatchConfig(callback func(*Config)) error {
	// This is a simplified implementation
	// In a production system, you'd use a file watcher library like fsnotify

	// Get initial modification time
	initialInfo, err := os.Stat(cm.configPath)
	if err != nil {
		return fmt.Errorf("failed to stat config file: %w", err)
	}

	lastModTime := initialInfo.ModTime()

	// Start watching in a goroutine
	go func() {
		ticker := time.NewTicker(1 * time.Second)
		defer ticker.Stop()

		for range ticker.C {
			info, err := os.Stat(cm.configPath)
			if err != nil {
				continue // File might have been deleted temporarily
			}

			if info.ModTime().After(lastModTime) {
				lastModTime = info.ModTime()

				// Reload configuration
				config, err := cm.LoadConfig()
				if err != nil {
					// Log error but continue watching
					continue
				}

				// Call callback with new configuration
				callback(config)
			}
		}
	}()

	return nil
}

// ResetToDefaults resets configuration to default values
func (cm *ConfigManager) ResetToDefaults() error {
	return cm.SaveConfig(cm.defaultConfig)
}

// BackupConfig creates a backup of the current configuration
func (cm *ConfigManager) BackupConfig() error {
	if _, err := os.Stat(cm.configPath); os.IsNotExist(err) {
		return fmt.Errorf("config file does not exist")
	}

	backupPath := cm.configPath + ".backup." + time.Now().Format("20060102-150405")

	data, err := os.ReadFile(cm.configPath)
	if err != nil {
		return fmt.Errorf("failed to read config file: %w", err)
	}

	if err := os.WriteFile(backupPath, data, 0644); err != nil {
		return fmt.Errorf("failed to create backup: %w", err)
	}

	return nil
}

// GetConfigPath returns the path to the configuration file
func (cm *ConfigManager) GetConfigPath() string {
	return cm.configPath
}

// GetDefaultConfig returns the default configuration
func (cm *ConfigManager) GetDefaultConfig() *Config {
	return cm.defaultConfig
}

