   290→// applyMigrations applies any necessary configuration migrations
   291→func (cm *ConfigManager) applyMigrations(config *Config) error {
   292→	// Get current schema version (assume 1 if not present)
   293→	currentVersion := 1 // This would be read from the config in a real implementation
   294→
   295→	// Apply migrations in sequence
   296→	for currentVersion < cm.schemaVersion {
   297→		migrated := false
   298→		for _, rule := range cm.migrationRules {
   299→			if rule.FromVersion == currentVersion {
   300→				if err := rule.Migrate(config); err != nil {
   301→					return fmt.Errorf("migration from version %d to %d failed: %w", 
   302→						rule.FromVersion, rule.ToVersion, err)
   303→				}
   304→				currentVersion = rule.ToVersion
   305→				migrated = true
   306→				break
   307→			}
   308→		}
   309→		
   310→		if !migrated {
   311→			return fmt.Errorf("no migration path found from version %d to %d", 
   312→				currentVersion, cm.schemaVersion)
   313→		}
   314→	}
   315→
   316→	return nil
   317→}
