            Name:        "Primary Color",
            Description: "Main accent color for the interface",
            Type:        ItemTypeColor,
            Value:       currentTheme.Primary,
            ConfigPath:  "theme.primary",
            OnChange: func(value interface{}) tea.Cmd {
                return sp.updateFieldValue("theme.primary", value)
            },
        },
        // ... more theme items
    }
}
```

### 4. Navigation Integration Updates

#### View Registration Enhancement

```go
