}

// GetViewInfo returns information about a specific view
func (vr *ViewRouter) GetViewInfo(viewType ViewType) (ViewInfo, bool) {
	info, exists := vr.viewInfo[viewType]
	return info, exists
}

// GetAllViewInfo returns information about all views
func (vr *ViewRouter) GetAllViewInfo() []ViewInfo {
	views := make([]ViewInfo, 0, len(vr.viewInfo))

	// Return in a specific order
	order := []ViewType{
		ViewOverview,
		ViewSystemMonitor,
		ViewPortScanner,
		ViewPackageManager,
		ViewContainerMgmt,
		ViewAIAssistant,
		ViewBashTerminal,
		ViewSettings,
	}

	for _, viewType := range order {
		if info, exists := vr.viewInfo[viewType]; exists {
			views = append(views, info)
		}
	}

	return views
}

// HandleKeyBinding handles key bindings for view switching
func (vr *ViewRouter) HandleKeyBinding(key string) tea.Cmd {
	// Map key bindings to views
	keyToView := map[string]ViewType{
		"1": ViewOverview,
		"2": ViewSystemMonitor,
		"3": ViewPortScanner,
		"4": ViewPackageManager,
		"5": ViewSettings,
		"6": ViewAIAssistant,
		"!": ViewBashTerminal,
	}

	if viewType, exists := keyToView[key]; exists {
		return func() tea.Msg {
			return ViewSwitchMsg{
				View:     viewType,
				Previous: vr.viewManager.GetCurrentView(),
			}
		}
	}

	// Handle tab for next view
	if key == "tab" {
		nextView := vr.getNextView()
		return func() tea.Msg {
			return ViewSwitchMsg{
				View:     nextView,
				Previous: vr.viewManager.GetCurrentView(),
			}
		}
	}

	// Handle back navigation
	if key == "esc" {
		return func() tea.Msg {
			return ViewSwitchMsg{
				View:     vr.viewManager.GetPreviousView(),
				Previous: vr.viewManager.GetCurrentView(),
			}
		}
	}

	return nil
}

// getNextView returns the next view in sequence
func (vr *ViewRouter) getNextView() ViewType {
	order := []ViewType{
		ViewOverview,
		ViewSystemMonitor,
		ViewPortScanner,
		ViewPackageManager,
		ViewContainerMgmt,
		ViewAIAssistant,
		ViewBashTerminal,
	}

	currentView := vr.viewManager.GetCurrentView()
	for i, view := range order {
		if view == currentView {
			return order[(i+1)%len(order)]
		}
	}

	return ViewOverview
}

// RenderViewBreadcrumb renders a breadcrumb showing current view path
func (vr *ViewRouter) RenderViewBreadcrumb() string {
	currentView := vr.viewManager.GetCurrentView()
	info, exists := vr.GetViewInfo(currentView)
	if !exists {
		return ""
	}

	breadcrumbStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Faint(true)

	iconStyle := lipgloss.NewStyle().
		Foreground(info.Color)

	nameStyle := lipgloss.NewStyle().
		Foreground(info.Color).
		Bold(true)

	return fmt.Sprintf("%s %s > %s",
		iconStyle.Render(info.Icon),
		breadcrumbStyle.Render("Terminal Multitool"),
		nameStyle.Render(info.Name),
	)
}

