package main

import (
	"math"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// MainModel represents the main application model following Bubble Tea's Elm Architecture
type MainModel struct {
	// View management
	viewRouter *ViewRouter

	// UI state
	showHelp     bool
	showSettings bool
	width        int
	height       int

	// Shared state
	config      *Config
	keyBindings KeyBindings

	// UI components
	statusBar     *StatusBarModel
	navigation    *NavigationModel
	notifications *NotificationModel

	// Application state
	initialized bool
	quitting    bool
	err         error

	// Visual effects state (maintaining cyberpunk aesthetic)
	frame         int
	pulsePhase    float64
	glowIntensity float64
}

// StatusBarModel handles the status bar display
type StatusBarModel struct {
	status    string
	color     lipgloss.Color
	timestamp time.Time
	width     int
}

// NavigationModel handles the navigation component
type NavigationModel struct {
	views        []ViewInfo
	currentIndex int
	width        int
	showIcons    bool
}

// ViewInfo contains information about each view
type ViewInfo struct {
	Type        ViewType
	Name        string
	Icon        string
	Color       lipgloss.Color
	KeyBinding  string
	Description string
}

// NotificationModel handles notifications display
type NotificationModel struct {
	notifications []Notification
	maxVisible    int
	width         int
	height        int
}

// Notification represents a single notification
type Notification struct {
	ID        string
	Message   string
	Level     NotificationLevel
	Source    string
	Timestamp time.Time
	Duration  time.Duration
	Visible   bool
}

// NewMainModel creates a new main model with default configuration
func NewMainModel() *MainModel {
	config := DefaultConfig()
	viewRouter := NewViewRouter()
	navigation := NewNavigationModel()

	// Initialize navigation with view info from router
	navigation.views = viewRouter.GetAllViewInfo()

	return &MainModel{
		viewRouter:    viewRouter,
		config:        config,
		keyBindings:   config.KeyBindings,
		statusBar:     NewStatusBarModel(),
		navigation:    navigation,
		notifications: NewNotificationModel(),
		initialized:   false,
		quitting:      false,
		glowIntensity: 0.5,
		pulsePhase:    0,
	}
}

// NewStatusBarModel creates a new status bar model
func NewStatusBarModel() *StatusBarModel {
	return &StatusBarModel{
		status:    "Ready",
		color:     lipgloss.Color("#10b981"), // success color
		timestamp: time.Now(),
	}
}

// NewNavigationModel creates a new navigation model
func NewNavigationModel() *NavigationModel {
	// Views will be populated by the main model from the view router
	return &NavigationModel{
		views:        []ViewInfo{}, // Will be populated later
		currentIndex: 0,
		showIcons:    true,
	}
}

// NewNotificationModel creates a new notification model
func NewNotificationModel() *NotificationModel {
	return &NotificationModel{
		notifications: make([]Notification, 0),
		maxVisible:    5,
	}
}

// Init initializes the main model and all tool components
func (m *MainModel) Init() tea.Cmd {
	var cmds []tea.Cmd

	// Initialize and register tool components
	systemMonitor := NewSystemMonitorModel()
	m.viewRouter.GetViewManager().RegisterComponent(ViewSystemMonitor, systemMonitor)
	cmds = append(cmds, systemMonitor.Init())

	// Initialize UI components
	cmds = append(cmds, m.statusBar.Init())
	cmds = append(cmds, m.navigation.Init())
	cmds = append(cmds, m.notifications.Init())

	// Start the tick for visual effects
	cmds = append(cmds, m.tickCmd())

	m.initialized = true

	return tea.Batch(cmds...)
}

// Update handles messages and routes them to appropriate components
func (m *MainModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	var cmds []tea.Cmd

	// Handle global messages first
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		m.setSize(msg.Width, msg.Height)
		return m, nil

	case tea.KeyMsg:
		// Handle global key bindings
		if cmd := m.handleGlobalKeys(msg); cmd != nil {
			return m, cmd
		}

	case ConfigUpdateMsg:
		m.config = msg.Config
		m.keyBindings = msg.Config.KeyBindings

	case NotificationMsg:
		m.notifications.AddNotification(msg)

	case StatusUpdateMsg:
		m.statusBar.UpdateStatus(msg.Status, msg.Color)

	case ErrorMsg:
		m.handleError(msg)

	case tickMsg:
		m.updateVisualEffects()
		cmds = append(cmds, m.tickCmd())
	}

	// Route message through view manager
	_, routerCmds := m.viewRouter.GetViewManager().RouteMessage(msg)
	cmds = append(cmds, routerCmds...)

	// Update UI components
	statusBar, statusCmd := m.statusBar.Update(msg)
	m.statusBar = statusBar.(*StatusBarModel)
	if statusCmd != nil {
		cmds = append(cmds, statusCmd)
	}

	navigation, navCmd := m.navigation.Update(msg)
	m.navigation = navigation.(*NavigationModel)
	if navCmd != nil {
		cmds = append(cmds, navCmd)
	}

	notifications, notifCmd := m.notifications.Update(msg)
	m.notifications = notifications.(*NotificationModel)
	if notifCmd != nil {
		cmds = append(cmds, notifCmd)
	}

	return m, tea.Batch(cmds...)
}

// View renders the main application interface
func (m *MainModel) View() string {
	if m.quitting {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6366f1")).
			Align(lipgloss.Center).
			Render("Disconnecting from the matrix...\n")
	}

	if !m.initialized || m.width == 0 || m.height == 0 {
		return "Initializing quantum interface..."
	}

	// Build the main layout
	header := m.renderHeader()
	navigation := m.navigation.View()
	content := m.renderContent()
	statusBar := m.statusBar.View()
	notifications := m.notifications.View()

	// Combine all components
	layout := lipgloss.JoinVertical(lipgloss.Left,
		header,
		navigation,
		content,
		statusBar,
	)

	// Overlay notifications if any
	if len(m.notifications.notifications) > 0 {
		layout = m.overlayNotifications(layout, notifications)
	}

	return layout
}

// Helper methods for the main model

// setSize updates the size for all components
func (m *MainModel) setSize(width, height int) {
	m.statusBar.SetSize(width, 1)
	m.navigation.SetSize(width, 3)
	m.notifications.SetSize(width, height/4)

	// Set size for view manager and all tool components
	contentHeight := height - 6 // Account for header, nav, status
	m.viewRouter.GetViewManager().SetSize(width, contentHeight)
}

// handleGlobalKeys processes global key bindings
func (m *MainModel) handleGlobalKeys(msg tea.KeyMsg) tea.Cmd {
	key := msg.String()

	// Check quit keys
	for _, quitKey := range m.keyBindings.Quit {
		if key == quitKey {
			m.quitting = true
			return tea.Quit
		}
	}

	// Use view router for key binding handling
	if cmd := m.viewRouter.HandleKeyBinding(key); cmd != nil {
		return cmd
	}

	// Check help toggle
	for _, helpKey := range m.keyBindings.Help {
		if key == helpKey {
			m.showHelp = !m.showHelp
			return nil
		}
	}

	return nil
}

// handleError processes error messages
func (m *MainModel) handleError(errMsg ErrorMsg) {
	// Convert error to notification
	level := NotificationError
	switch errMsg.Level {
	case ErrorLevelInfo:
		level = NotificationInfo
	case ErrorLevelWarning:
		level = NotificationWarning
	case ErrorLevelError, ErrorLevelCritical:
		level = NotificationError
	}

	notification := NotificationMsg{
		Message: errMsg.Err.Error(),
		Level:   level,
		Source:  errMsg.Source,
		Time:    time.Now(),
	}

	m.notifications.AddNotification(notification)
}

// updateVisualEffects updates the visual effects state
func (m *MainModel) updateVisualEffects() {
	m.frame++
	m.pulsePhase += 0.05
	if m.pulsePhase > 6.28 { // 2π
		m.pulsePhase = 0
	}
	m.glowIntensity = 0.3 + 0.2*math.Sin(m.pulsePhase)
}

// tickMsg is defined in main.go

// tickCmd returns a command that sends tick messages
func (m *MainModel) tickCmd() tea.Cmd {
	return tea.Tick(time.Millisecond*50, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

// renderHeader renders the application header
func (m *MainModel) renderHeader() string {
	title := "⟨ QUANTUM COMMAND CENTER ⟩"

	titleStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Align(lipgloss.Center).
		Width(m.width)

	timestamp := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Align(lipgloss.Right).
		Width(m.width).
		Render(time.Now().Format("◉ 15:04:05"))

	return lipgloss.JoinVertical(lipgloss.Left,
		titleStyle.Render(title),
		timestamp,
		"",
	)
}

// renderContent renders the main content area
func (m *MainModel) renderContent() string {
	currentView := m.viewRouter.GetViewManager().GetCurrentView()

	if currentView == ViewOverview {
		return m.renderOverview()
	}

	// Render active component through view manager
	if component := m.viewRouter.GetViewManager().GetCurrentComponent(); component != nil {
		return component.View()
	}

	// Fallback for unimplemented views
	return lipgloss.NewStyle().
		Align(lipgloss.Center).
		Foreground(lipgloss.Color("#94a3b8")).
		Render("View not implemented yet")
}

// renderOverview renders the overview dashboard
func (m *MainModel) renderOverview() string {
	// Placeholder for overview - will be enhanced in later tasks
	return lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#6366f1")).
		Padding(2).
		Align(lipgloss.Center).
		Width(m.width - 4).
		Height(m.height - 8).
		Render("🚀 OVERVIEW DASHBOARD\n\nWelcome to the Terminal Multitool\n\nUse number keys 1-6 to navigate between tools\nPress ? for help")
}

// overlayNotifications overlays notifications on the main layout
func (m *MainModel) overlayNotifications(layout, notifications string) string {
	// Simple overlay for now - can be enhanced later
	return layout + "\n" + notifications
}

