   390→func (cm *ConfigManager) validatePortRange(rangeStr string) error {
   391→	parts := strings.Split(rangeStr, "-")
   392→	if len(parts) != 2 {
   393→		return fmt.Errorf("port range must be in format 'start-end'")
   394→	}
   395→
   396→	start, err := parsePort(parts[0])
   397→	if err != nil {
   398→		return fmt.Errorf("invalid start port: %w", err)
   399→	}
   400→
   401→	end, err := parsePort(parts[1])
   402→	if err != nil {
   403→		return fmt.Errorf("invalid end port: %w", err)
   404→	}
   405→
   406→	if start > end {
   407→		return fmt.Errorf("start port must be less than or equal to end port")
   408→	}
   409→
   410→	return nil
   411→}
