   413→func parsePort(portStr string) (int, error) {
   414→	port := 0
   415→	for _, r := range portStr {
   416→		if r < '0' || r > '9' {
   417→			return 0, fmt.Errorf("port must be numeric")
   418→		}
   419→		port = port*10 + int(r-'0')
   420→	}
   421→
   422→	if port < 1 || port > 65535 {
   423→		return 0, fmt.Errorf("port must be between 1 and 65535")
   424→	}
   425→
   426→	return port, nil
   427→}
