   519→// WatchConfig watches for configuration file changes and reloads automatically
   520→func (cm *ConfigManager) WatchConfig(callback func(*Config)) error {
   521→	// This is a simplified implementation
   522→	// In a production system, you'd use a file watcher library like fsnotify
   523→	
   524→	// Get initial modification time
   525→	initialInfo, err := os.Stat(cm.configPath)
   526→	if err != nil {
   527→		return fmt.Errorf("failed to stat config file: %w", err)
   528→	}
   529→	
   530→	lastModTime := initialInfo.ModTime()
   531→	
   532→	// Start watching in a goroutine
   533→	go func() {
   534→		ticker := time.NewTicker(1 * time.Second)
   535→		defer ticker.Stop()
   536→		
   537→		for range ticker.C {
   538→			info, err := os.Stat(cm.configPath)
   539→			if err != nil {
   540→				continue // File might have been deleted temporarily
   541→			}
   542→			
   543→			if info.ModTime().After(lastModTime) {
   544→				lastModTime = info.ModTime()
   545→				
   546→				// Reload configuration
   547→				config, err := cm.LoadConfig()
   548→				if err != nil {
   549→					// Log error but continue watching
   550→					continue
   551→				}
   552→				
   553→				// Call callback with new configuration
   554→				callback(config)
   555→			}
   556→		}
   557→	}()
   558→	
   559→	return nil
   560→}
