   310→// LoadAlerts loads alerts within a time range
   311→func (ds *DataStore) LoadAlerts(from, to time.Time, limit int) ([]*PersistedAlert, error) {
   312→	files, err := os.ReadDir(ds.alertHistory.dataDir)
   313→	if err != nil {
