   391→// CleanupOldData removes old data based on retention policies
   392→func (ds *DataStore) CleanupOldData(retentionPolicies map[string]time.Duration) error {
   393→	now := time.Now()
   394→
   395→	// Cleanup scan results
   396→	if retention, exists := retentionPolicies["scan_results"]; exists {
   397→		cutoff := now.Add(-retention)
   398→		if err := ds.cleanupScanResults(cutoff); err != nil {
   399→			return fmt.Errorf("failed to cleanup scan results: %w", err)
   400→		}
   401→	}
   402→
   403→	// Cleanup alert history
   404→	if retention, exists := retentionPolicies["alert_history"]; exists {
   405→		cutoff := now.Add(-retention)
   406→		if err := ds.cleanupAlertHistory(cutoff); err != nil {
   407→			return fmt.Errorf("failed to cleanup alert history: %w", err)
   408→		}
   409→	}
   410→
   411→	// Cleanup metric history
   412→	if retention, exists := retentionPolicies["metric_history"]; exists {
   413→		cutoff := now.Add(-retention)
   414→		if err := ds.cleanupMetricHistory(cutoff); err != nil {
   415→			return fmt.Errorf("failed to cleanup metric history: %w", err)
   416→		}
   417→	}
   418→
   419→	// Cleanup old session backups
   420→	if retention, exists := retentionPolicies["session_backups"]; exists {
   421→		cutoff := now.Add(-retention)
   422→		if err := ds.cleanupSessionBackups(cutoff); err != nil {
   423→			return fmt.Errorf("failed to cleanup session backups: %w", err)
   424→		}
   425→	}
   426→
   427→	return nil
   428→}
   429→
   430→// cleanupScanResults removes scan results older than the cutoff time
   431→func (ds *DataStore) cleanupScanResults(cutoff time.Time) error {
   432→	return ds.cleanupDirectory(ds.scanResults.dataDir, cutoff, func(data interface{}) time.Time {
   433→		if result, ok := data.(*PersistedScanResult); ok {
   434→			return result.Timestamp
   435→		}
   436→		return time.Time{}
   437→	})
   438→}
   439→
   440→// cleanupAlertHistory removes alerts older than the cutoff time
   441→func (ds *DataStore) cleanupAlertHistory(cutoff time.Time) error {
   442→	return ds.cleanupDirectory(ds.alertHistory.dataDir, cutoff, func(data interface{}) time.Time {
   443→		if alert, ok := data.(*PersistedAlert); ok {
   444→			return alert.Timestamp
   445→		}
   446→		return time.Time{}
   447→	})
   448→}
   449→
   450→// cleanupMetricHistory removes old data points from metric files
   451→func (ds *DataStore) cleanupMetricHistory(cutoff time.Time) error {
   452→	names, err := ds.ListMetricNames()
   453→	if err != nil {
   454→		return err
   455→	}
   456→
   457→	for _, name := range names {
   458→		data, err := ds.LoadMetricHistory(name)
   459→		if err != nil {
   460→			continue // Skip corrupted files
   461→		}
   462→
   463→		// Filter out old data points
   464→		var newDataPoints []PersistedMetricDataPoint
   465→		for _, point := range data.DataPoints {
   466→			if point.Timestamp.After(cutoff) {
   467→				newDataPoints = append(newDataPoints, point)
   468→			}
   469→		}
   470→
   471→		if len(newDataPoints) != len(data.DataPoints) {
   472→			data.DataPoints = newDataPoints
   473→			// Recalculate min/max values
   474→			if len(newDataPoints) > 0 {
   475→				data.MinValue = newDataPoints[0].Value
   476→				data.MaxValue = newDataPoints[0].Value
   477→				for _, point := range newDataPoints {
   478→					if point.Value < data.MinValue {
   479→						data.MinValue = point.Value
   480→					}
   481→					if point.Value > data.MaxValue {
   482→						data.MaxValue = point.Value
   483→					}
   484→				}
   485→			}
   486→			
   487→			// Save updated data
   488→			ds.SaveMetricHistory(data)
   489→		}
   490→	}
   491→
   492→	return nil
   493→}
   494→
   495→// cleanupSessionBackups removes old session backup files
   496→func (ds *DataStore) cleanupSessionBackups(cutoff time.Time) error {
   497→	files, err := os.ReadDir(ds.sessionState.dataDir)
   498→	if err != nil {
   499→		return err
   500→	}
   501→
   502→	for _, file := range files {
   503→		if file.IsDir() || !file.Type().IsRegular() {
   504→			continue
   505→		}
   506→
   507→		// Only remove backup files, not the current session
   508→		if file.Name() == "session_current.json" {
   509→			continue
   510→		}
   511→
   512→		info, err := file.Info()
   513→		if err != nil {
   514→			continue
   515→		}
   516→
   517→		if info.ModTime().Before(cutoff) {
   518→			fullPath := filepath.Join(ds.sessionState.dataDir, file.Name())
   519→			os.Remove(fullPath)
   520→		}
   521→	}
   522→
   523→	return nil
   524→}
   525→
   526→// Generic cleanup helper
   527→func (ds *DataStore) cleanupDirectory(dir string, cutoff time.Time, getTimestamp func(interface{}) time.Time) error {
   528→	files, err := os.ReadDir(dir)
   529→	if err != nil {
   530→		return err
   531→	}
   532→
   533→	for _, file := range files {
   534→		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
   535→			continue
   536→		}
   537→
   538→		fullPath := filepath.Join(dir, file.Name())
   539→		
   540→		// Try to parse the file to get timestamp
   541→		var data interface{}
   542→		if err := ds.readJSONFile(fullPath, &data); err != nil {
   543→			// If we can't parse it, check file modification time
   544→			info, err := file.Info()
   545→			if err == nil && info.ModTime().Before(cutoff) {
   546→				os.Remove(fullPath)
   547→			}
   548→			continue
   549→		}
   550→
   551→		timestamp := getTimestamp(data)
   552→		if !timestamp.IsZero() && timestamp.Before(cutoff) {
   553→			os.Remove(fullPath)
   554→		}
   555→	}
   556→
   557→	return nil
   558→}
   559→
   560→// Utility methods
   561→
   562→// writeJSONFile writes data to a JSON file atomically
   563→func (ds *DataStore) writeJSONFile(filepath string, data interface{}) error {
   564→	// Marshal data to JSON
   565→	jsonData, err := json.MarshalIndent(data, "", "  ")
   566→	if err != nil {
   567→		return fmt.Errorf("failed to marshal JSON: %w", err)
   568→	}
   569→
   570→	// Write to temporary file first
   571→	tempFile := filepath + ".tmp"
   572→	if err := os.WriteFile(tempFile, jsonData, 0644); err != nil {
   573→		return fmt.Errorf("failed to write temporary file: %w", err)
   574→	}
   575→
   576→	// Atomic move
   577→	if err := os.Rename(tempFile, filepath); err != nil {
   578→		os.Remove(tempFile) // Cleanup
   579→		return fmt.Errorf("failed to move file: %w", err)
   580→	}
   581→
   582→	return nil
   583→}
   584→
   585→// readJSONFile reads and unmarshals data from a JSON file
   586→func (ds *DataStore) readJSONFile(filepath string, data interface{}) error {
   587→	content, err := os.ReadFile(filepath)
   588→	if err != nil {
   589→		return fmt.Errorf("failed to read file: %w", err)
   590→	}
   591→
   592→	if err := json.Unmarshal(content, data); err != nil {
   593→		return fmt.Errorf("failed to unmarshal JSON: %w", err)
   594→	}
   595→
   596→	return nil
   597→}
