   605→func (ds *DataStore) GetDataDirectory() string {
   606→	return ds.dataDir
   607→}
   608→
   609→// GetStorageStats returns storage usage statistics
   610→func (ds *DataStore) GetStorageStats() (map[string]interface{}, error) {
   611→	stats := make(map[string]interface{})
   612→	
   613→	// Count files in each directory
   614→	dirs := map[string]string{
   615→		"scans":    ds.scanResults.dataDir,
   616→		"sessions": ds.sessionState.dataDir,
   617→		"alerts":   ds.alertHistory.dataDir,
   618→		"metrics":  ds.metricHistory.dataDir,
   619→	}
   620→	
   621→	totalSize := int64(0)
   622→	totalFiles := 0
   623→	
   624→	for name, dir := range dirs {
   625→		files, err := os.ReadDir(dir)
   626→		if err != nil {
   627→			continue
   628→		}
   629→		
   630→		dirSize := int64(0)
   631→		fileCount := 0
   632→		
   633→		for _, file := range files {
   634→			if !file.IsDir() {
   635→				info, err := file.Info()
   636→				if err == nil {
   637→					dirSize += info.Size()
   638→				}
   639→				fileCount++
   640→			}
   641→		}
   642→		
   643→		stats[name] = map[string]interface{}{
   644→			"file_count": fileCount,
   645→			"size_bytes": dirSize,
   646→		}
   647→		
   648→		totalSize += dirSize
   649→		totalFiles += fileCount
   650→	}
   651→	
   652→	stats["total"] = map[string]interface{}{
   653→		"file_count": totalFiles,
   654→		"size_bytes": totalSize,
   655→	}
   656→	
   657→	return stats, nil
   658→}

