package main

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

// DataStore handles persistent storage of application data
type DataStore struct {
	dataDir       string
	scanResults   *ScanResultStore
	sessionState  *SessionStateStore
	alertHistory  *AlertHistoryStore
	metricHistory *MetricHistoryStore
}

// ScanResultStore manages port scan result persistence
type ScanResultStore struct {
	dataDir string
}

// SessionStateStore manages session state persistence
type SessionStateStore struct {
	dataDir string
}

// AlertHistoryStore manages alert history persistence
type AlertHistoryStore struct {
	dataDir string
}

// MetricHistoryStore manages metric history persistence
type MetricHistoryStore struct {
	dataDir string
}

// Persisted data structures

// PersistedScanResult represents a stored scan result
type PersistedScanResult struct {
	ID          string                 `json:"id"`
	Timestamp   time.Time              `json:"timestamp"`
	Target      string                 `json:"target"`
	PortRanges  []string               `json:"port_ranges"`
	ScanType    string                 `json:"scan_type"`
	Results     []PersistedPortResult  `json:"results"`
	Duration    time.Duration          `json:"duration"`
	Status      string                 `json:"status"`
	Metadata    map[string]interface{} `json:"metadata"`
}

// PersistedPortResult represents a single port scan result
type PersistedPortResult struct {
	Port         int       `json:"port"`
	Protocol     string    `json:"protocol"`
	State        string    `json:"state"`
	Service      string    `json:"service"`
	Banner       string    `json:"banner"`
	ResponseTime int64     `json:"response_time_ms"`
	Timestamp    time.Time `json:"timestamp"`
}

// PersistedSessionState represents the application session state
type PersistedSessionState struct {
	ID            string                 `json:"id"`
	Timestamp     time.Time              `json:"timestamp"`
	CurrentView   string                 `json:"current_view"`
	WindowSize    WindowSize             `json:"window_size"`
	ViewStates    map[string]interface{} `json:"view_states"`
	Preferences   map[string]interface{} `json:"preferences"`
	RecentScans   []string               `json:"recent_scans"`
	RecentTargets []string               `json:"recent_targets"`
}

// WindowSize represents the terminal window dimensions
type WindowSize struct {
	Width  int `json:"width"`
	Height int `json:"height"`
}

// PersistedAlert represents a stored alert
type PersistedAlert struct {
	ID          string                 `json:"id"`
	Type        string                 `json:"type"`
	Level       string                 `json:"level"`
	Message     string                 `json:"message"`
	Description string                 `json:"description"`
	Timestamp   time.Time              `json:"timestamp"`
	Source      string                 `json:"source"`
	Value       float64                `json:"value"`
	Threshold   float64                `json:"threshold"`
	Unit        string                 `json:"unit"`
	Resolved    bool                   `json:"resolved"`
	ResolvedAt  *time.Time             `json:"resolved_at,omitempty"`
	Actions     []string               `json:"actions"`
	Metadata    map[string]interface{} `json:"metadata"`
}

// PersistedMetricData represents stored metric history
type PersistedMetricData struct {
	MetricName  string                     `json:"metric_name"`
	Unit        string                     `json:"unit"`
	DataPoints  []PersistedMetricDataPoint `json:"data_points"`
	MinValue    float64                    `json:"min_value"`
	MaxValue    float64                    `json:"max_value"`
	LastUpdated time.Time                  `json:"last_updated"`
	Metadata    map[string]interface{}     `json:"metadata"`
}

// PersistedMetricDataPoint represents a single metric data point
type PersistedMetricDataPoint struct {
	Timestamp time.Time              `json:"timestamp"`
	Value     float64                `json:"value"`
	Label     string                 `json:"label"`
	Metadata  map[string]interface{} `json:"metadata,omitempty"`
}

// NewDataStore creates a new data store instance
func NewDataStore(dataDir string) (*DataStore, error) {
	// Ensure data directory exists
	if err := os.MkdirAll(dataDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create data directory: %w", err)
	}

	// Create subdirectories
	scanDir := filepath.Join(dataDir, "scans")
	sessionDir := filepath.Join(dataDir, "sessions")
	alertDir := filepath.Join(dataDir, "alerts")
	metricDir := filepath.Join(dataDir, "metrics")

	for _, dir := range []string{scanDir, sessionDir, alertDir, metricDir} {
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, fmt.Errorf("failed to create directory %s: %w", dir, err)
		}
	}

	return &DataStore{
		dataDir:       dataDir,
		scanResults:   &ScanResultStore{dataDir: scanDir},
		sessionState:  &SessionStateStore{dataDir: sessionDir},
		alertHistory:  &AlertHistoryStore{dataDir: alertDir},
		metricHistory: &MetricHistoryStore{dataDir: metricDir},
	}, nil
}

// Scan result persistence methods

// SaveScanResult saves a scan result to persistent storage
func (ds *DataStore) SaveScanResult(result *PersistedScanResult) error {
	if result.ID == "" {
		result.ID = generateID()
	}
	if result.Timestamp.IsZero() {
		result.Timestamp = time.Now()
	}

	filename := fmt.Sprintf("scan_%s_%s.json", 
		result.Timestamp.Format("20060102_150405"), result.ID)
	filepath := filepath.Join(ds.scanResults.dataDir, filename)

	return ds.writeJSONFile(filepath, result)
}

// LoadScanResult loads a scan result by ID
func (ds *DataStore) LoadScanResult(id string) (*PersistedScanResult, error) {
	// Find the file by ID
	files, err := os.ReadDir(ds.scanResults.dataDir)
	if err != nil {
		return nil, fmt.Errorf("failed to read scan directory: %w", err)
	}

	for _, file := range files {
		if !file.IsDir() && filepath.Ext(file.Name()) == ".json" {
			fullPath := filepath.Join(ds.scanResults.dataDir, file.Name())

			var result PersistedScanResult
			if err := ds.readJSONFile(fullPath, &result); err != nil {
				continue // Skip corrupted files
			}

			if result.ID == id {
				return &result, nil
			}
		}
	}

	return nil, fmt.Errorf("scan result with ID %s not found", id)
}

// ListScanResults returns a list of all scan results, optionally filtered
func (ds *DataStore) ListScanResults(limit int, after time.Time) ([]*PersistedScanResult, error) {
	files, err := os.ReadDir(ds.scanResults.dataDir)
	if err != nil {
		return nil, fmt.Errorf("failed to read scan directory: %w", err)
	}

	var results []*PersistedScanResult
	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
			continue
		}

		fullPath := filepath.Join(ds.scanResults.dataDir, file.Name())

		var result PersistedScanResult
		if err := ds.readJSONFile(fullPath, &result); err != nil {
			continue // Skip corrupted files
		}

		if result.Timestamp.After(after) {
			results = append(results, &result)
		}

		if limit > 0 && len(results) >= limit {
			break
		}
	}

	return results, nil
}

// DeleteScanResult deletes a scan result by ID
func (ds *DataStore) DeleteScanResult(id string) error {
	// Find and delete the file
	files, err := os.ReadDir(ds.scanResults.dataDir)
	if err != nil {
		return fmt.Errorf("failed to read scan directory: %w", err)
	}

	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
			continue
		}

		fullPath := filepath.Join(ds.scanResults.dataDir, file.Name())

		var result PersistedScanResult
		if err := ds.readJSONFile(fullPath, &result); err != nil {
			continue
		}

		if result.ID == id {
			return os.Remove(fullPath)
		}
	}

	return fmt.Errorf("scan result with ID %s not found", id)
}

// Session state persistence methods

// SaveSessionState saves the current session state
func (ds *DataStore) SaveSessionState(state *PersistedSessionState) error {
	if state.ID == "" {
		state.ID = "current"
	}
	state.Timestamp = time.Now()

	filename := "session_current.json"
	filepath := filepath.Join(ds.sessionState.dataDir, filename)

	return ds.writeJSONFile(filepath, state)
}

// LoadSessionState loads the most recent session state
func (ds *DataStore) LoadSessionState() (*PersistedSessionState, error) {
	filename := "session_current.json"
	filepath := filepath.Join(ds.sessionState.dataDir, filename)

	var state PersistedSessionState
	if err := ds.readJSONFile(filepath, &state); err != nil {
		return nil, err
	}

	return &state, nil
}

// BackupSessionState creates a backup of the current session state
func (ds *DataStore) BackupSessionState() error {
	currentState, err := ds.LoadSessionState()
	if err != nil {
		return fmt.Errorf("failed to load current session state: %w", err)
	}

	backupFilename := fmt.Sprintf("session_backup_%s.json", 
		time.Now().Format("20060102_150405"))
	backupPath := filepath.Join(ds.sessionState.dataDir, backupFilename)

	return ds.writeJSONFile(backupPath, currentState)
}

// Alert history persistence methods

// SaveAlert saves an alert to persistent storage
func (ds *DataStore) SaveAlert(alert *PersistedAlert) error {
	if alert.ID == "" {
		alert.ID = generateID()
	}

	filename := fmt.Sprintf("alert_%s_%s.json", 
		alert.Timestamp.Format("20060102_150405"), alert.ID)
	filepath := filepath.Join(ds.alertHistory.dataDir, filename)

	return ds.writeJSONFile(filepath, alert)
}

// LoadAlerts loads alerts within a time range
func (ds *DataStore) LoadAlerts(from, to time.Time, limit int) ([]*PersistedAlert, error) {
	files, err := os.ReadDir(ds.alertHistory.dataDir)
	if err != nil {
		return nil, fmt.Errorf("failed to read alert directory: %w", err)
	}

	var alerts []*PersistedAlert
	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
			continue
		}

		fullPath := filepath.Join(ds.alertHistory.dataDir, file.Name())

		var alert PersistedAlert
		if err := ds.readJSONFile(fullPath, &alert); err != nil {
			continue // Skip corrupted files
		}

		if alert.Timestamp.After(from) && alert.Timestamp.Before(to) {
			alerts = append(alerts, &alert)
		}

		if limit > 0 && len(alerts) >= limit {
			break
		}
	}

	return alerts, nil
}

// Metric history persistence methods

// SaveMetricHistory saves metric history data
func (ds *DataStore) SaveMetricHistory(data *PersistedMetricData) error {
	filename := fmt.Sprintf("metric_%s.json", data.MetricName)
	filepath := filepath.Join(ds.metricHistory.dataDir, filename)

	data.LastUpdated = time.Now()
	return ds.writeJSONFile(filepath, data)
}

// LoadMetricHistory loads metric history data by name
func (ds *DataStore) LoadMetricHistory(metricName string) (*PersistedMetricData, error) {
	filename := fmt.Sprintf("metric_%s.json", metricName)
	filepath := filepath.Join(ds.metricHistory.dataDir, filename)

	var data PersistedMetricData
	if err := ds.readJSONFile(filepath, &data); err != nil {
		return nil, err
	}

	return &data, nil
}

// ListMetricNames returns a list of all available metric names
func (ds *DataStore) ListMetricNames() ([]string, error) {
	files, err := os.ReadDir(ds.metricHistory.dataDir)
	if err != nil {
		return nil, fmt.Errorf("failed to read metric directory: %w", err)
	}

	var names []string
	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
			continue
		}

		name := file.Name()
		if len(name) > 12 && name[:7] == "metric_" && name[len(name)-5:] == ".json" {
			metricName := name[7 : len(name)-5]
			names = append(names, metricName)
		}
	}

	return names, nil
}

// Data cleanup methods

// CleanupOldData removes old data based on retention policies
func (ds *DataStore) CleanupOldData(retentionPolicies map[string]time.Duration) error {
	now := time.Now()

	// Cleanup scan results
	if retention, exists := retentionPolicies["scan_results"]; exists {
		cutoff := now.Add(-retention)
		if err := ds.cleanupScanResults(cutoff); err != nil {
			return fmt.Errorf("failed to cleanup scan results: %w", err)
		}
	}

	// Cleanup alert history
	if retention, exists := retentionPolicies["alert_history"]; exists {
		cutoff := now.Add(-retention)
		if err := ds.cleanupAlertHistory(cutoff); err != nil {
			return fmt.Errorf("failed to cleanup alert history: %w", err)
		}
	}

	// Cleanup metric history
	if retention, exists := retentionPolicies["metric_history"]; exists {
		cutoff := now.Add(-retention)
		if err := ds.cleanupMetricHistory(cutoff); err != nil {
			return fmt.Errorf("failed to cleanup metric history: %w", err)
		}
	}

	// Cleanup old session backups
	if retention, exists := retentionPolicies["session_backups"]; exists {
		cutoff := now.Add(-retention)
		if err := ds.cleanupSessionBackups(cutoff); err != nil {
			return fmt.Errorf("failed to cleanup session backups: %w", err)
		}
	}

	return nil
}

// cleanupScanResults removes scan results older than the cutoff time
func (ds *DataStore) cleanupScanResults(cutoff time.Time) error {
	return ds.cleanupDirectory(ds.scanResults.dataDir, cutoff, func(data interface{}) time.Time {
		if result, ok := data.(*PersistedScanResult); ok {
			return result.Timestamp
		}
		return time.Time{}
	})
}

// cleanupAlertHistory removes alerts older than the cutoff time
func (ds *DataStore) cleanupAlertHistory(cutoff time.Time) error {
	return ds.cleanupDirectory(ds.alertHistory.dataDir, cutoff, func(data interface{}) time.Time {
		if alert, ok := data.(*PersistedAlert); ok {
			return alert.Timestamp
		}
		return time.Time{}
	})
}

// cleanupMetricHistory removes old data points from metric files
func (ds *DataStore) cleanupMetricHistory(cutoff time.Time) error {
	names, err := ds.ListMetricNames()
	if err != nil {
		return err
	}

	for _, name := range names {
		data, err := ds.LoadMetricHistory(name)
		if err != nil {
			continue // Skip corrupted files
		}

		// Filter out old data points
		var newDataPoints []PersistedMetricDataPoint
		for _, point := range data.DataPoints {
			if point.Timestamp.After(cutoff) {
				newDataPoints = append(newDataPoints, point)
			}
		}

		if len(newDataPoints) != len(data.DataPoints) {
			data.DataPoints = newDataPoints
			// Recalculate min/max values
			if len(newDataPoints) > 0 {
				data.MinValue = newDataPoints[0].Value
				data.MaxValue = newDataPoints[0].Value
				for _, point := range newDataPoints {
					if point.Value < data.MinValue {
						data.MinValue = point.Value
					}
					if point.Value > data.MaxValue {
						data.MaxValue = point.Value
					}
				}
			}

			// Save updated data
			ds.SaveMetricHistory(data)
		}
	}

	return nil
}

// cleanupSessionBackups removes old session backup files
func (ds *DataStore) cleanupSessionBackups(cutoff time.Time) error {
	files, err := os.ReadDir(ds.sessionState.dataDir)
	if err != nil {
		return err
	}

	for _, file := range files {
		if file.IsDir() || !file.Type().IsRegular() {
			continue
		}

		// Only remove backup files, not the current session
		if file.Name() == "session_current.json" {
			continue
		}

		info, err := file.Info()
		if err != nil {
			continue
		}

		if info.ModTime().Before(cutoff) {
			fullPath := filepath.Join(ds.sessionState.dataDir, file.Name())
			os.Remove(fullPath)
		}
	}

	return nil
}

// Generic cleanup helper
func (ds *DataStore) cleanupDirectory(dir string, cutoff time.Time, getTimestamp func(interface{}) time.Time) error {
	files, err := os.ReadDir(dir)
	if err != nil {
		return err
	}

	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != ".json" {
			continue
		}

		fullPath := filepath.Join(dir, file.Name())

		// Try to parse the file to get timestamp
		var data interface{}
		if err := ds.readJSONFile(fullPath, &data); err != nil {
			// If we can't parse it, check file modification time
			info, err := file.Info()
			if err == nil && info.ModTime().Before(cutoff) {
				os.Remove(fullPath)
			}
			continue
		}

		timestamp := getTimestamp(data)
		if !timestamp.IsZero() && timestamp.Before(cutoff) {
			os.Remove(fullPath)
		}
	}

	return nil
}

// Utility methods

// writeJSONFile writes data to a JSON file atomically
func (ds *DataStore) writeJSONFile(filepath string, data interface{}) error {
	// Marshal data to JSON
	jsonData, err := json.MarshalIndent(data, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal JSON: %w", err)
	}

	// Write to temporary file first
	tempFile := filepath + ".tmp"
	if err := os.WriteFile(tempFile, jsonData, 0644); err != nil {
		return fmt.Errorf("failed to write temporary file: %w", err)
	}

	// Atomic move
	if err := os.Rename(tempFile, filepath); err != nil {
		os.Remove(tempFile) // Cleanup
		return fmt.Errorf("failed to move file: %w", err)
	}

	return nil
}

// readJSONFile reads and unmarshals data from a JSON file
func (ds *DataStore) readJSONFile(filepath string, data interface{}) error {
	content, err := os.ReadFile(filepath)
	if err != nil {
		return fmt.Errorf("failed to read file: %w", err)
	}

	if err := json.Unmarshal(content, data); err != nil {
		return fmt.Errorf("failed to unmarshal JSON: %w", err)
	}

	return nil
}

// generateID generates a unique ID for records
func generateID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

// GetDataDirectory returns the base data directory path
func (ds *DataStore) GetDataDirectory() string {
	return ds.dataDir
}

// GetStorageStats returns storage usage statistics
func (ds *DataStore) GetStorageStats() (map[string]interface{}, error) {
	stats := make(map[string]interface{})

	// Count files in each directory
	dirs := map[string]string{
		"scans":    ds.scanResults.dataDir,
		"sessions": ds.sessionState.dataDir,
		"alerts":   ds.alertHistory.dataDir,
		"metrics":  ds.metricHistory.dataDir,
	}

	totalSize := int64(0)
	totalFiles := 0

	for name, dir := range dirs {
		files, err := os.ReadDir(dir)
		if err != nil {
			continue
		}

		dirSize := int64(0)
		fileCount := 0

		for _, file := range files {
			if !file.IsDir() {
				info, err := file.Info()
				if err == nil {
					dirSize += info.Size()
				}
				fileCount++
			}
		}

		stats[name] = map[string]interface{}{
			"file_count": fileCount,
			"size_bytes": dirSize,
		}

		totalSize += dirSize
		totalFiles += fileCount
	}

	stats["total"] = map[string]interface{}{
		"file_count": totalFiles,
		"size_bytes": totalSize,
	}

	return stats, nil
}

package main

import (
	"time"

	tea "github.com/charmbracelet/bubbletea"
