package main

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"errors"
	"fmt"
	"net"
	"os"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// SecurityValidator provides comprehensive input validation and security checks
// Implements Task 8.1 - Security Validation Layer
type SecurityValidator struct {
	MaxHostnameLength    int
	MaxPortRangeLength   int
	MaxCommandLength     int
	MaxPathLength        int
	MaxUsernameLength    int
	MaxConfigValueLength int
}

// NewSecurityValidator creates a new security validator with default limits
func NewSecurityValidator() *SecurityValidator {
	return &SecurityValidator{
		MaxHostnameLength:    253, // RFC 1035 limit
		MaxPortRangeLength:   100, // e.g., "1-65535,8000-8100"
		MaxCommandLength:     1000,
		MaxPathLength:        4096, // Common filesystem limit
		MaxUsernameLength:    32,
		MaxConfigValueLength: 1000,
	}
}

// Security validation errors
var (
	ErrInvalidHostname      = errors.New("invalid hostname format")
	ErrInvalidIP            = errors.New("invalid IP address format")
	ErrInvalidPort          = errors.New("invalid port number")
	ErrInvalidPortRange     = errors.New("invalid port range format")
	ErrInvalidPath          = errors.New("invalid file path")
	ErrInvalidCommand       = errors.New("invalid command format")
	ErrInputTooLong         = errors.New("input exceeds maximum length")
	ErrContainsInvalidChars = errors.New("input contains invalid characters")
	ErrPrivilegedOperation  = errors.New("operation requires elevated privileges")
	ErrInsecurePath         = errors.New("path contains potentially dangerous elements")
)

// ValidateHostname validates hostname format and length
func (sv *SecurityValidator) ValidateHostname(hostname string) error {
	if len(hostname) == 0 {
		return ErrInvalidHostname
	}

	if len(hostname) > sv.MaxHostnameLength {
		return ErrInputTooLong
	}

	// Check for valid hostname pattern (RFC 1123)
	hostnameRegex := regexp.MustCompile(`^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$`)
	if !hostnameRegex.MatchString(hostname) {
		return ErrInvalidHostname
	}

	return nil
}

// ValidateIPAddress validates IP address format (IPv4 and IPv6)
func (sv *SecurityValidator) ValidateIPAddress(ip string) error {
	if net.ParseIP(ip) == nil {
		return ErrInvalidIP
	}
	return nil
}

// ValidatePort validates port number (1-65535)
func (sv *SecurityValidator) ValidatePort(port int) error {
	if port < 1 || port > 65535 {
		return ErrInvalidPort
	}
	return nil
}

// ValidatePortString validates port string and converts to int
func (sv *SecurityValidator) ValidatePortString(portStr string) (int, error) {
	port, err := strconv.Atoi(portStr)
	if err != nil {
		return 0, ErrInvalidPort
	}
	return port, sv.ValidatePort(port)
}

// ValidatePortRange validates port range format (e.g., "80-443", "22", "1000-2000,8080")
func (sv *SecurityValidator) ValidatePortRange(portRange string) error {
	if len(portRange) == 0 {
		return ErrInvalidPortRange
	}

	if len(portRange) > sv.MaxPortRangeLength {
		return ErrInputTooLong
	}

	// Split by comma for multiple ranges
	ranges := strings.Split(portRange, ",")

	for _, r := range ranges {
		r = strings.TrimSpace(r)
		if strings.Contains(r, "-") {
			// Range format: "start-end"
			parts := strings.Split(r, "-")
			if len(parts) != 2 {
				return ErrInvalidPortRange
			}

			start, err := sv.ValidatePortString(strings.TrimSpace(parts[0]))
			if err != nil {
				return err
			}

			end, err := sv.ValidatePortString(strings.TrimSpace(parts[1]))
			if err != nil {
				return err
			}

			if start > end {
				return ErrInvalidPortRange
			}
		} else {
			// Single port
			if _, err := sv.ValidatePortString(r); err != nil {
				return err
			}
		}
	}

	return nil
}

// ValidateFilePath validates file paths for security issues
func (sv *SecurityValidator) ValidateFilePath(path string) error {
	if len(path) == 0 {
		return ErrInvalidPath
	}

	if len(path) > sv.MaxPathLength {
		return ErrInputTooLong
	}

	// Check for directory traversal attempts
	cleanPath := filepath.Clean(path)
	if strings.Contains(cleanPath, "..") {
		return ErrInsecurePath
	}

	// Check for null bytes (path injection)
	if strings.Contains(path, "\x00") {
		return ErrContainsInvalidChars
	}

	// Validate path doesn't access sensitive system directories
	dangerousPaths := []string{
		"/etc/passwd",
		"/etc/shadow",
		"/etc/hosts",
		"/proc",
		"/sys",
		"C:\\Windows\\System32",
		"C:\\Windows\\SysWOW64",
	}

	// Check dangerous paths directly without relying on filepath.Abs
	// since it may not work correctly for cross-platform paths
	lowerPath := strings.ToLower(cleanPath)
	for _, dangerous := range dangerousPaths {
		lowerDangerous := strings.ToLower(dangerous)
		if strings.HasPrefix(lowerPath, lowerDangerous) {
			return ErrInsecurePath
		}
	}

	// Also check absolute path if it can be resolved
	absPath, err := filepath.Abs(cleanPath)
	if err == nil {
		lowerAbsPath := strings.ToLower(absPath)
		for _, dangerous := range dangerousPaths {
			lowerDangerous := strings.ToLower(dangerous)
			if strings.HasPrefix(lowerAbsPath, lowerDangerous) {
				return ErrInsecurePath
			}
		}
	}

	return nil
}

// ValidateCommand validates command strings for shell injection
func (sv *SecurityValidator) ValidateCommand(command string) error {
	if len(command) == 0 {
		return ErrInvalidCommand
	}

	if len(command) > sv.MaxCommandLength {
		return ErrInputTooLong
	}

	// Check for dangerous characters that could enable shell injection
	dangerousChars := []string{";", "&", "|", "`", "$", "(", ")", "{", "}", "<", ">", "\n", "\r"}

	for _, char := range dangerousChars {
		if strings.Contains(command, char) {
			return ErrContainsInvalidChars
		}
	}

	return nil
}

// ValidateUsername validates usernames for system operations
func (sv *SecurityValidator) ValidateUsername(username string) error {
	if len(username) == 0 {
		return errors.New("username cannot be empty")
	}

	if len(username) > sv.MaxUsernameLength {
		return ErrInputTooLong
	}

	// Username should only contain alphanumeric characters, hyphens, and underscores
	usernameRegex := regexp.MustCompile(`^[a-zA-Z0-9_-]+$`)
	if !usernameRegex.MatchString(username) {
		return ErrContainsInvalidChars
	}

	return nil
}

// ValidateConfigValue validates configuration values
func (sv *SecurityValidator) ValidateConfigValue(key, value string) error {
	if len(value) > sv.MaxConfigValueLength {
		return ErrInputTooLong
	}

	// Check for control characters (except tab and newline in some cases)
	for _, r := range value {
		if r < 32 && r != 9 && r != 10 && r != 13 {
			return ErrContainsInvalidChars
		}
	}

	// Special validation for specific config keys
	switch strings.ToLower(key) {
	case "api_key", "password", "secret":
		return sv.validateSensitiveValue(value)
	case "timeout", "interval":
		return sv.validateDurationValue(value)
	case "port":
		_, err := sv.ValidatePortString(value)
		return err
	case "host", "hostname":
		return sv.ValidateHostname(value)
	}

	return nil
}

// validateSensitiveValue validates sensitive configuration values
func (sv *SecurityValidator) validateSensitiveValue(value string) error {
	if len(value) == 0 {
		return nil // Allow empty sensitive values (will use defaults)
	}

	// Basic validation for API keys/secrets
	if len(value) < 8 {
		return errors.New("sensitive value too short (minimum 8 characters)")
	}

	return nil
}

// validateDurationValue validates time duration values
func (sv *SecurityValidator) validateDurationValue(value string) error {
	_, err := time.ParseDuration(value)
	if err != nil {
		return fmt.Errorf("invalid duration format: %w", err)
	}
	return nil
}

// PermissionChecker handles permission validation for operations
type PermissionChecker struct {
	currentUser string
	isRoot      bool
}

// NewPermissionChecker creates a new permission checker
func NewPermissionChecker() *PermissionChecker {
	currentUser := os.Getenv("USER")
	if currentUser == "" {
		currentUser = os.Getenv("USERNAME") // Windows
	}

	isRoot := os.Geteuid() == 0 // Unix/Linux check for root

	return &PermissionChecker{
		currentUser: currentUser,
		isRoot:      isRoot,
	}
}

// CheckPrivilegedOperation checks if current user can perform privileged operations
func (pc *PermissionChecker) CheckPrivilegedOperation(operation string) error {
	privilegedOps := []string{
		"kill_process",
		"modify_system_files",
		"bind_privileged_port",
		"access_system_logs",
		"modify_network_config",
	}

	for _, privOp := range privilegedOps {
		if operation == privOp && !pc.isRoot {
			return ErrPrivilegedOperation
		}
	}

	return nil
}

// CheckFileAccess checks if current user can access a file/directory
func (pc *PermissionChecker) CheckFileAccess(path string, accessType string) error {
	info, err := os.Stat(path)
	if err != nil {
		if os.IsNotExist(err) {
			return errors.New("file does not exist")
		}
		return fmt.Errorf("cannot access file: %w", err)
	}

	mode := info.Mode()

	switch accessType {
	case "read":
		if mode&0004 == 0 && !pc.isRoot { // Others read permission
			return errors.New("insufficient permissions to read file")
		}
	case "write":
		if mode&0002 == 0 && !pc.isRoot { // Others write permission
			return errors.New("insufficient permissions to write file")
		}
	case "execute":
		if mode&0001 == 0 && !pc.isRoot { // Others execute permission
			return errors.New("insufficient permissions to execute file")
		}
	}

	return nil
}

// SecureStorage handles secure storage of sensitive data
type SecureStorage struct {
	keyDerivationSalt []byte
}

// NewSecureStorage creates a new secure storage instance
func NewSecureStorage() (*SecureStorage, error) {
	salt := make([]byte, 32)
	if _, err := rand.Read(salt); err != nil {
		return nil, fmt.Errorf("failed to generate salt: %w", err)
	}

	return &SecureStorage{
		keyDerivationSalt: salt,
	}, nil
}

// HashSensitiveData hashes sensitive data for secure storage
func (ss *SecureStorage) HashSensitiveData(data string) string {
	hasher := sha256.New()
	hasher.Write([]byte(data))
	hasher.Write(ss.keyDerivationSalt)
	return base64.StdEncoding.EncodeToString(hasher.Sum(nil))
}

// SanitizeForLog sanitizes sensitive data for logging
func (ss *SecureStorage) SanitizeForLog(data string) string {
	if len(data) <= 4 {
		return strings.Repeat("*", len(data))
	}

	// Show first 2 and last 2 characters, mask the rest
	return data[:2] + strings.Repeat("*", len(data)-4) + data[len(data)-2:]
}

// ValidateAndSanitizeInput performs comprehensive input validation and sanitization
func ValidateAndSanitizeInput(inputType string, value string) (string, error) {
	validator := NewSecurityValidator()

	switch inputType {
	case "hostname":
		err := validator.ValidateHostname(value)
		return strings.TrimSpace(strings.ToLower(value)), err

	case "ip":
		err := validator.ValidateIPAddress(value)
		return strings.TrimSpace(value), err

	case "port_range":
		err := validator.ValidatePortRange(value)
		return strings.TrimSpace(value), err

	case "file_path":
		err := validator.ValidateFilePath(value)
		return filepath.Clean(value), err

	case "command":
		err := validator.ValidateCommand(value)
		return strings.TrimSpace(value), err

	case "username":
		err := validator.ValidateUsername(value)
		return strings.TrimSpace(strings.ToLower(value)), err

	case "config_value":
		// For config values, we need the key as well, but we'll do basic validation
		if len(value) > validator.MaxConfigValueLength {
			return "", ErrInputTooLong
		}
		return strings.TrimSpace(value), nil

	default:
		return strings.TrimSpace(value), nil
	}
}

