// ViewType represents the different tool views available in the multitool
type ViewType int

const (
	ViewOverview ViewType = iota
	ViewSystemMonitor
	ViewPortScanner
	ViewPackageManager
	ViewContainerMgmt
	ViewAIAssistant
	ViewBashTerminal
	ViewSettings
)

// String returns the string representation of ViewType
func (v ViewType) String() string {
	switch v {
	case ViewOverview:
		return "overview"
	case ViewSystemMonitor:
		return "system"
	case ViewPortScanner:
		return "scanner"
	case ViewPackageManager:
		return "packages"
	case ViewContainerMgmt:
		return "containers"
	case ViewAIAssistant:
		return "ai"
	case ViewBashTerminal:
		return "bash"
	case ViewSettings:
		return "settings"
	default:
		return "unknown"
	}
}

// ToolComponent defines the interface that all tool components must implement
type ToolComponent interface {
	// Init initializes the component and returns initial commands
	Init() tea.Cmd

	// Update handles messages and returns updated model and commands
	Update(msg tea.Msg) (ToolComponent, tea.Cmd)

	// View renders the component's interface
	View() string

	// SetSize updates the component's dimensions
	SetSize(width, height int)

	// GetViewType returns the component's view type
	GetViewType() ViewType

	// IsActive returns whether the component is currently active
	IsActive() bool

	// SetActive sets the component's active state
	SetActive(active bool)
}

// Global message types for inter-component communication
type (
	// tickMsg represents a tick message for animations and updates
	tickMsg time.Time
	// ViewSwitchMsg is sent when switching between different tool views
	ViewSwitchMsg struct {
		View     ViewType
		Previous ViewType
	}

	// ConfigUpdateMsg is sent when configuration changes
	ConfigUpdateMsg struct {
		Config *Config
	}

	// NotificationMsg is sent to display notifications to the user
	NotificationMsg struct {
		Message string
		Level   NotificationLevel
		Source  string
		Time    time.Time
	}

	// StatusUpdateMsg is sent to update the status bar
	StatusUpdateMsg struct {
		Status string
		Color  lipgloss.Color
	}

	// ErrorMsg wraps errors for consistent error handling
	ErrorMsg struct {
		Err    error
		Source string
		Level  ErrorLevel
	}

	// DataUpdateMsg is sent when shared data is updated
	DataUpdateMsg struct {
		Type string
		Data interface{}
	}

	// SaveConfigMsg is a message to trigger saving the configuration.
	SaveConfigMsg struct{}
)

// NotificationLevel represents the severity of notifications
type NotificationLevel int

const (
	NotificationInfo NotificationLevel = iota
	NotificationWarning
	NotificationError
	NotificationSuccess
)

// String returns the string representation of NotificationLevel
func (n NotificationLevel) String() string {
	switch n {
	case NotificationInfo:
		return "info"
	case NotificationWarning:
		return "warning"
	case NotificationError:
		return "error"
	case NotificationSuccess:
		return "success"
	default:
		return "unknown"
	}
}

// ErrorLevel represents the severity of errors
type ErrorLevel int

const (
	ErrorLevelInfo ErrorLevel = iota
	ErrorLevelWarning
	ErrorLevelError
	ErrorLevelCritical
)

// String returns the string representation of ErrorLevel
func (e ErrorLevel) String() string {
	switch e {
	case ErrorLevelInfo:
		return "info"
	case ErrorLevelWarning:
		return "warning"
	case ErrorLevelError:
		return "error"
	case ErrorLevelCritical:
		return "critical"
	default:
		return "unknown"
	}
}

