// validateField validates a single configuration field
func (cm *ConfigManager) validateField(field string, value interface{}) error {
	validator, exists := cm.validators[field]
	if !exists {
		return nil // No validator for this field
	}

	if err := validator(value); err != nil {
		return &ConfigurationError{
			Field:   field,
			Message: err.Error(),
			Value:   value,
		}
	}

	return nil
}

// applyMigrations applies any necessary configuration migrations
func (cm *ConfigManager) applyMigrations(config *Config) error {
	// Use config.Version instead of assuming version 1
	currentVersion := config.Version
	if currentVersion == 0 {
		currentVersion = 1 // Default to version 1 for legacy configs
	}

	// Apply migrations in sequence
	for currentVersion < cm.schemaVersion {
		migrated := false
		for _, rule := range cm.migrationRules {
			if rule.FromVersion == currentVersion {
				if err := rule.Migrate(config); err != nil {
					return fmt.Errorf("migration from version %d to %d failed: %w",
						rule.FromVersion, rule.ToVersion, err)
				}
				currentVersion = rule.ToVersion
				config.Version = currentVersion
				migrated = true
				break
			}
		}

		if !migrated {
			return fmt.Errorf("no migration path found from version %d to %d",
				currentVersion, cm.schemaVersion)
		}
	}

	return nil
}

// applyEnvironmentOverrides applies environment variable overrides to config
func (cm *ConfigManager) applyEnvironmentOverrides(config *Config) {
	// General settings overrides
	if val := os.Getenv("QUANTUM_APP_NAME"); val != "" {
		config.General.AppName = val
	}
	if val := os.Getenv("QUANTUM_STARTUP_VIEW"); val != "" {
		config.General.StartupView = val
	}
	if val := os.Getenv("QUANTUM_AUTO_SAVE"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			config.General.AutoSave = parsed
		}
	}

	// Theme overrides
	if val := os.Getenv("QUANTUM_THEME"); val != "" {
		config.Theme.CurrentTheme = val
	}
	if val := os.Getenv("QUANTUM_GLOW_INTENSITY"); val != "" {
		if parsed, err := strconv.ParseFloat(val, 64); err == nil {
			config.Theme.GlowIntensity = parsed
		}
	}

	// Advanced UI overrides
	if val := os.Getenv("QUANTUM_ANIMATION_SPEED"); val != "" {
		config.AdvancedUI.AnimationSpeed = val
	}
	if val := os.Getenv("QUANTUM_PERFORMANCE_MODE"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			config.AdvancedUI.PerformanceMode = parsed
		}
	}

	// Log level override
	if val := os.Getenv("QUANTUM_LOG_LEVEL"); val != "" {
		config.LogLevel = val
	}

	// Data directory override
	if val := os.Getenv("QUANTUM_DATA_DIR"); val != "" {
		config.DataDirectory = val
	}
}

// Configuration field validators

func (cm *ConfigManager) validateNonEmptyString(value interface{}) error {
	str, ok := value.(string)
	if !ok {
		return fmt.Errorf("value must be a string")
	}
	if strings.TrimSpace(str) == "" {
		return fmt.Errorf("value cannot be empty")
	}
	return nil
}

func (cm *ConfigManager) validateStartupView(value interface{}) error {
	view, ok := value.(string)
	if !ok {
		return fmt.Errorf("startup view must be a string")
	}

	validViews := []string{"overview", "system", "scanner", "packages", "containers", "ai", "bash", "settings"}
	for _, valid := range validViews {
		if view == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid startup view, must be one of: %s", strings.Join(validViews, ", "))
}

func (cm *ConfigManager) validateAnimationSpeed(value interface{}) error {
	speed, ok := value.(string)
	if !ok {
		return fmt.Errorf("animation speed must be a string")
	}

	validSpeeds := []string{"Off", "Slow", "Normal", "Fast"}
	for _, valid := range validSpeeds {
		if speed == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid animation speed, must be one of: %s", strings.Join(validSpeeds, ", "))
}

func (cm *ConfigManager) validateFloatRange(min, max float64) ConfigValidator {
	return func(value interface{}) error {
		val, ok := value.(float64)
		if !ok {
			return fmt.Errorf("value must be a number")
		}
		if val < min || val > max {
			return fmt.Errorf("value must be between %.2f and %.2f", min, max)
		}
		return nil
	}
}

func (cm *ConfigManager) validateIntRange(min, max int) ConfigValidator {
	return func(value interface{}) error {
		val, ok := value.(int)
		if !ok {
			return fmt.Errorf("value must be an integer")
		}
		if val < min || val > max {
			return fmt.Errorf("value must be between %d and %d", min, max)
		}
		return nil
	}
}

func (cm *ConfigManager) validateHotkeyString(value interface{}) error {
	hotkey, ok := value.(string)
	if !ok {
		return fmt.Errorf("hotkey must be a string")
	}

	if strings.TrimSpace(hotkey) == "" {
		return fmt.Errorf("hotkey cannot be empty")
	}

	// Basic validation - hotkeys can contain letters, numbers, and common key names
	// More comprehensive validation would require parsing the hotkey format
	return nil
}

func (cm *ConfigManager) validateDuration(value interface{}) error {
	switch v := value.(type) {
	case time.Duration:
		if v <= 0 {
			return fmt.Errorf("duration must be positive")
		}
	case string:
		if _, err := time.ParseDuration(v); err != nil {
			return fmt.Errorf("invalid duration format: %w", err)
		}
	default:
		return fmt.Errorf("duration must be a time.Duration or string")
	}
	return nil
}

func (cm *ConfigManager) validatePositiveInt(value interface{}) error {
	intVal, ok := value.(int)
	if !ok {
		return fmt.Errorf("value must be an integer")
	}

	if intVal <= 0 {
		return fmt.Errorf("value must be positive")
	}

	return nil
}

func (cm *ConfigManager) validatePortRanges(value interface{}) error {
	ranges, ok := value.([]string)
	if !ok {
		return fmt.Errorf("port ranges must be a string slice")
	}

	for _, rangeStr := range ranges {
		if err := cm.validatePortRange(rangeStr); err != nil {
			return fmt.Errorf("invalid port range '%s': %w", rangeStr, err)
		}
	}

	return nil
}

func (cm *ConfigManager) validatePortRange(rangeStr string) error {
	parts := strings.Split(rangeStr, "-")
	if len(parts) != 2 {
		return fmt.Errorf("port range must be in format 'start-end'")
	}

	start, err := parsePort(parts[0])
	if err != nil {
		return fmt.Errorf("invalid start port: %w", err)
	}

	end, err := parsePort(parts[1])
	if err != nil {
		return fmt.Errorf("invalid end port: %w", err)
	}

	if start > end {
		return fmt.Errorf("start port must be less than or equal to end port")
	}

	return nil
}

func parsePort(portStr string) (int, error) {
	port := 0
	for _, r := range portStr {
		if r < '0' || r > '9' {
			return 0, fmt.Errorf("port must be numeric")
		}
		port = port*10 + int(r-'0')
	}

	if port < 1 || port > 65535 {
		return 0, fmt.Errorf("port must be between 1 and 65535")
	}

	return port, nil
}

func (cm *ConfigManager) validateAIProvider(value interface{}) error {
	provider, ok := value.(string)
	if !ok {
		return fmt.Errorf("AI provider must be a string")
	}

	validProviders := []string{"openai", "anthropic", "local", "none"}
	for _, valid := range validProviders {
		if provider == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid AI provider, must be one of: %s", strings.Join(validProviders, ", "))
}

func (cm *ConfigManager) validateTemperature(value interface{}) error {
	temp, ok := value.(float64)
	if !ok {
		return fmt.Errorf("temperature must be a number")
	}

	if temp < 0.0 || temp > 2.0 {
		return fmt.Errorf("temperature must be between 0.0 and 2.0")
	}

	return nil
}

func (cm *ConfigManager) validateLogLevel(value interface{}) error {
	level, ok := value.(string)
	if !ok {
		return fmt.Errorf("log level must be a string")
	}

	validLevels := []string{"debug", "info", "warn", "error"}
	for _, valid := range validLevels {
		if level == valid {
			return nil
		}
	}

	return fmt.Errorf("invalid log level, must be one of: %s", strings.Join(validLevels, ", "))
}

func (cm *ConfigManager) validateDirectory(value interface{}) error {
	dir, ok := value.(string)
	if !ok {
		return fmt.Errorf("directory must be a string")
	}

	if dir == "" {
		return fmt.Errorf("directory cannot be empty")
	}

	// Expand tilde
	if strings.HasPrefix(dir, "~/") {
		homeDir, err := os.UserHomeDir()
		if err != nil {
			return fmt.Errorf("cannot resolve home directory: %w", err)
		}
		dir = filepath.Join(homeDir, dir[2:])
	}

	// Check if directory exists or can be created
	info, err := os.Stat(dir)
	if err != nil {
		// Try to create the directory
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("cannot create directory: %w", err)
		}
		return nil
	}

	if !info.IsDir() {
		return fmt.Errorf("path exists but is not a directory")
	}

	// Check if directory is writable
	testFile := filepath.Join(dir, ".write_test")
	if err := os.WriteFile(testFile, []byte("test"), 0644); err != nil {
		return fmt.Errorf("directory is not writable: %w", err)
	}
	os.Remove(testFile) // Cleanup

	return nil
}

// Settings accessor and update methods

// UpdateSetting updates a specific setting and optionally saves the config
func (cm *ConfigManager) UpdateSetting(config *Config, section, key string, value interface{}) error {
	switch section {
	case "general":
		return cm.updateGeneralSetting(config, key, value)
	case "theme":
		return cm.updateThemeSetting(config, key, value)
	case "advanced_ui":
		return cm.updateAdvancedUISetting(config, key, value)
	case "keybindings":
		return cm.updateKeyBindingSetting(config, key, value)
