   557→func (cm *ConfigManager) validatePortRanges(value interface{}) error {
   558→	ranges, ok := value.([]string)
   559→	if !ok {
   560→		return fmt.Errorf("port ranges must be a string slice")
   561→	}
   562→
   563→	for _, rangeStr := range ranges {
   564→		if err := cm.validatePortRange(rangeStr); err != nil {
   565→			return fmt.Errorf("invalid port range '%s': %w", rangeStr, err)
   566→		}
   567→	}
