// Profile management methods

// CreateProfile creates a new configuration profile
func (cm *ConfigManager) CreateProfile(config *Config, name string) error {
	if name == "" {
		return fmt.Errorf("profile name cannot be empty")
	}

	// Check if profile already exists
	for _, profile := range config.Profiles {
		if profile.Name == name {
			return fmt.Errorf("profile '%s' already exists", name)
		}
	}

	// Create new profile with current config
	newProfile := Profile{
		Name:   name,
		Config: *config, // Copy current config
	}

	config.Profiles = append(config.Profiles, newProfile)
	return nil
}

// DeleteProfile removes a configuration profile
func (cm *ConfigManager) DeleteProfile(config *Config, name string) error {
	if name == "default" {
		return fmt.Errorf("cannot delete default profile")
	}

	for i, profile := range config.Profiles {
		if profile.Name == name {
			config.Profiles = append(config.Profiles[:i], config.Profiles[i+1:]...)
			if config.ActiveProfile == name {
				config.ActiveProfile = "default"
			}
			return nil
		}
	}

	return fmt.Errorf("profile '%s' not found", name)
}

// SwitchProfile switches to a different configuration profile
func (cm *ConfigManager) SwitchProfile(config *Config, name string) error {
	if name == "default" {
		config.ActiveProfile = name
		return nil
	}

	for _, profile := range config.Profiles {
		if profile.Name == name {
			config.ActiveProfile = name
			return nil
		}
	}

	return fmt.Errorf("profile '%s' not found", name)
}

// GetActiveProfileConfig returns the configuration for the active profile
func (cm *ConfigManager) GetActiveProfileConfig(config *Config) *Config {
	if config.ActiveProfile == "default" || config.ActiveProfile == "" {
		return config
	}

	for _, profile := range config.Profiles {
		if profile.Name == config.ActiveProfile {
			return &profile.Config
		}
	}

	// Fallback to main config if active profile not found
	return config
}

// Hot reload functionality

// WatchConfig watches for configuration file changes and reloads automatically
func (cm *ConfigManager) WatchConfig(callback func(*Config)) error {
	// Get initial modification time
	initialInfo, err := os.Stat(cm.configPath)
	if err != nil {
		return fmt.Errorf("failed to stat config file: %w", err)
	}

	lastModTime := initialInfo.ModTime()

	// Start watching in a goroutine
	go func() {
		ticker := time.NewTicker(1 * time.Second)
		defer ticker.Stop()

		for range ticker.C {
			info, err := os.Stat(cm.configPath)
			if err != nil {
				continue // File might have been deleted temporarily
			}

			if info.ModTime().After(lastModTime) {
				lastModTime = info.ModTime()

				// Reload configuration
				config, err := cm.LoadConfig()
				if err != nil {
					// Log error but continue watching
					continue
				}

				// Call callback with new configuration
				callback(config)
			}
		}
	}()

	return nil
}

// ResetToDefaults resets configuration to default values
func (cm *ConfigManager) ResetToDefaults() error {
	return cm.SaveConfig(cm.defaultConfig)
}

// BackupConfig creates a backup of the current configuration
func (cm *ConfigManager) BackupConfig() error {
	if _, err := os.Stat(cm.configPath); os.IsNotExist(err) {
		return fmt.Errorf("config file does not exist")
	}

	backupPath := cm.configPath + ".backup." + time.Now().Format("20060102-150405")

	data, err := os.ReadFile(cm.configPath)
	if err != nil {
		return fmt.Errorf("failed to read config file: %w", err)
	}

	if err := os.WriteFile(backupPath, data, 0644); err != nil {
		return fmt.Errorf("failed to create backup: %w", err)
	}

	return nil
}

// GetConfigPath returns the path to the configuration file
func (cm *ConfigManager) GetConfigPath() string {
	return cm.configPath
}

// GetDefaultConfig returns the default configuration
func (cm *ConfigManager) GetDefaultConfig() *Config {
	return cm.defaultConfig
}

