package main

import (
	"fmt"
	"strings"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// SettingsPageModel implements a comprehensive settings interface
type SettingsPageModel struct {
	// Component state
	active bool
	width  int
	height int

	// Configuration reference
	config        *Config
	configManager *ConfigManager

	// Settings navigation
	currentSection SettingsSection
	selectedItem   int
	scrollOffset   int
	sections       []SettingsSection

	// Edit state
	editMode      bool
	editingItem   string
	editValue     string
	editCursorPos int

	// Theme manager reference
	themeManager *ThemeManager

	// Visual effects
	frame      int
	pulsePhase float64
}

// SettingsSection represents a category of settings
type SettingsSection int

const (
	SectionGeneral SettingsSection = iota
	SectionThemes
	SectionHotkeys
	SectionAdvanced
	SectionProfiles
	SectionAbout
)

// String returns the string representation of SettingsSection
func (s SettingsSection) String() string {
	switch s {
	case SectionGeneral:
		return "General"
	case SectionThemes:
		return "Themes"
	case SectionHotkeys:
		return "Hotkeys"
	case SectionAdvanced:
		return "Advanced"
	case SectionProfiles:
		return "Profiles"
	case SectionAbout:
		return "About"
	default:
		return "Unknown"
	}
}

// SettingsItem represents a configurable setting
type SettingsItem struct {
	Name        string
	Description string
	Type        SettingsItemType
	Value       interface{}
	Options     []string // For dropdown/selection items
	Min         float64  // For numeric items
	Max         float64  // For numeric items
	Step        float64  // For numeric items
	Action      func()   // For action buttons
	Section     string   // Config section for updating
	Key         string   // Config key for updating
}

// SettingsItemType represents the type of setting
type SettingsItemType int

const (
	ItemTypeString SettingsItemType = iota
	ItemTypeNumber
	ItemTypeBool
	ItemTypeSelection
	ItemTypeAction
	ItemTypeColor
	ItemTypeHotkey
)

// NewSettingsPageModel creates a new settings page component
func NewSettingsPageModel(themeManager *ThemeManager, configManager *ConfigManager, config *Config) *SettingsPageModel {
	sp := &SettingsPageModel{
		active:         false,
		config:         config,
		configManager:  configManager,
		currentSection: SectionGeneral,
		selectedItem:   0,
		scrollOffset:   0,
		editMode:       false,
		themeManager:   themeManager,
		pulsePhase:     0,
	}

	// Initialize sections
	sp.sections = []SettingsSection{
		SectionGeneral,
		SectionThemes,
		SectionHotkeys,
		SectionAdvanced,
		SectionProfiles,
		SectionAbout,
	}

	return sp
}

// ToolComponent interface implementation

// Init initializes the settings page component
func (sp *SettingsPageModel) Init() tea.Cmd {
	return sp.tickCmd()
}

// Update handles messages for the settings page
func (sp *SettingsPageModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case tea.KeyMsg:
		if !sp.active {
			return sp, nil
		}

		if cmd := sp.handleKeyMsg(msg); cmd != nil {
			cmds = append(cmds, cmd)
		}

	case ConfigUpdateMsg:
		sp.config = msg.Config

	case tickMsg:
		sp.updateVisualEffects()
		cmds = append(cmds, sp.tickCmd())
	}

	return sp, tea.Batch(cmds...)
}

// View renders the settings page interface
func (sp *SettingsPageModel) View() string {
	if !sp.active || sp.width == 0 || sp.height == 0 {
		return ""
	}

	return sp.renderSettings()
}

// SetSize updates the component dimensions
func (sp *SettingsPageModel) SetSize(width, height int) {
	sp.width = width
	sp.height = height
}

// GetViewType returns the component's view type
func (sp *SettingsPageModel) GetViewType() ViewType {
	return ViewSettings
}

// IsActive returns whether the component is currently active
func (sp *SettingsPageModel) IsActive() bool {
	return sp.active
}

// SetActive sets the component's active state
func (sp *SettingsPageModel) SetActive(active bool) {
	sp.active = active
}

// Key handling

// handleKeyMsg processes key messages for the settings page
func (sp *SettingsPageModel) handleKeyMsg(msg tea.KeyMsg) tea.Cmd {
	if sp.editMode {
		return sp.handleEditMode(msg)
	}

	switch msg.String() {
	case "left", "h":
		// Navigate to previous section
		if sp.currentSection > 0 {
			sp.currentSection--
			sp.selectedItem = 0
			sp.scrollOffset = 0
		}
		return nil

	case "right", "l":
		// Navigate to next section
		if int(sp.currentSection) < len(sp.sections)-1 {
			sp.currentSection++
			sp.selectedItem = 0
			sp.scrollOffset = 0
		}
		return nil

	case "up", "k":
		// Navigate up in current section
		if sp.selectedItem > 0 {
			sp.selectedItem--
			if sp.selectedItem < sp.scrollOffset {
				sp.scrollOffset = sp.selectedItem
			}
		}
		return nil

	case "down", "j":
		// Navigate down in current section
		items := sp.getSectionItems(sp.currentSection)
		if sp.selectedItem < len(items)-1 {
			sp.selectedItem++
			visibleItems := sp.height - 10
			if sp.selectedItem >= sp.scrollOffset+visibleItems {
				sp.scrollOffset = sp.selectedItem - visibleItems + 1
			}
		}
		return nil

	case "enter", " ":
		// Activate/edit selected item
		return sp.activateSelectedItem()

	case "esc":
		// Exit edit mode or go back
		if sp.editMode {
			sp.editMode = false
			return nil
		}
		// Could implement going back to main interface here
		return nil

	case "r":
		// Reset current section to defaults
		return sp.resetSectionToDefaults()

	case "s":
		// Save settings
		return sp.saveSettings()

	default:
		// Handle section hotkeys
		switch msg.String() {
		case "1":
			sp.currentSection = SectionGeneral
		case "2":
			sp.currentSection = SectionThemes
		case "3":
			sp.currentSection = SectionHotkeys
		case "4":
			sp.currentSection = SectionAdvanced
		case "5":
			sp.currentSection = SectionProfiles
		case "6":
			sp.currentSection = SectionAbout
		}
		sp.selectedItem = 0
		sp.scrollOffset = 0
		return nil
	}
}

// handleEditMode handles key input while editing a setting
func (sp *SettingsPageModel) handleEditMode(msg tea.KeyMsg) tea.Cmd {
	switch msg.String() {
	case "esc":
		sp.editMode = false
		return nil

	case "enter":
		// Save the edited value
		cmd := sp.saveEditedValue()
		sp.editMode = false
		return cmd

	case "left":
		if sp.editCursorPos > 0 {
			sp.editCursorPos--
		}
		return nil

	case "right":
		if sp.editCursorPos < len(sp.editValue) {
			sp.editCursorPos++
		}
		return nil

	case "backspace":
		if sp.editCursorPos > 0 {
			sp.editValue = sp.editValue[:sp.editCursorPos-1] + sp.editValue[sp.editCursorPos:]
			sp.editCursorPos--
		}
		return nil

	case "delete":
		if sp.editCursorPos < len(sp.editValue) {
			sp.editValue = sp.editValue[:sp.editCursorPos] + sp.editValue[sp.editCursorPos+1:]
		}
		return nil

	case "home", "ctrl+a":
		sp.editCursorPos = 0
		return nil

	case "end", "ctrl+e":
		sp.editCursorPos = len(sp.editValue)
		return nil

	default:
		// Regular character input
		if len(msg.String()) == 1 {
			char := msg.String()
			sp.editValue = sp.editValue[:sp.editCursorPos] + char + sp.editValue[sp.editCursorPos:]
			sp.editCursorPos++
		}
		return nil
	}
}

// Settings management

// getSectionItems returns the settings items for a specific section
func (sp *SettingsPageModel) getSectionItems(section SettingsSection) []SettingsItem {
	switch section {
	case SectionGeneral:
		return sp.getGeneralItems()
	case SectionThemes:
		return sp.getThemeItems()
	case SectionHotkeys:
		return sp.getHotkeyItems()
	case SectionAdvanced:
		return sp.getAdvancedItems()
	case SectionProfiles:
		return sp.getProfileItems()
	case SectionAbout:
		return sp.getAboutItems()
	default:
		return []SettingsItem{}
	}
}

// getGeneralItems returns general settings items
func (sp *SettingsPageModel) getGeneralItems() []SettingsItem {
	if sp.config == nil {
		return []SettingsItem{}
	}

	return []SettingsItem{
		{
			Name:        "Application Name",
			Description: "The display name for the application",
			Type:        ItemTypeString,
			Value:       sp.config.General.AppName,
			Section:     "general",
			Key:         "app_name",
		},
		{
			Name:        "Auto Save Settings",
			Description: "Automatically save settings when changed",
			Type:        ItemTypeBool,
			Value:       sp.config.General.AutoSave,
			Section:     "general",
			Key:         "auto_save",
		},
		{
			Name:        "Startup View",
			Description: "Which view to show when starting the application",
			Type:        ItemTypeSelection,
			Value:       sp.config.General.StartupView,
			Options:     []string{"overview", "system", "scanner", "packages", "containers", "ai", "bash", "settings"},
			Section:     "general",
			Key:         "startup_view",
		},
		{
			Name:        "Show Tooltips",
			Description: "Display helpful tooltips for UI elements",
			Type:        ItemTypeBool,
			Value:       sp.config.General.ShowTooltips,
			Section:     "general",
			Key:         "show_tooltips",
		},
		{
			Name:        "Confirm Destructive Actions",
